// Access Control Helper Functions
// Now uses centralized tier access configuration
// True only when user HAD a subscription that has since expired (not first-time users who never activated)
function isAppSubscriptionExpired() {
    // Admins and testers always have app access (Tier Four + admin tools); never lock the dashboard.
    if (currentUser && (currentUser.role === 'admin' || currentUser.role === 'tester')) {
        return false;
    }
    if (!currentSubscription) return false; // First-time user: never activated, allow free exploration/plan selection
    return currentSubscription.status !== 'active'; // Had subscription, now inactive/expired
}

function hasAccessToCoreFinishers() {
    if (currentUser && (currentUser.role === 'admin' || currentUser.role === 'tester')) return true;
    if (!currentSubscription || currentSubscription.status !== 'active') return false;
    // All tiers now have access (with different limits) - checked via config
    const tier = currentSubscription.tier;
    return window.hasAccessToFeature ? window.hasAccessToFeature(tier, 'core_finishers', currentSubscription) : true;
}

function hasAccessToStrengthWorkouts() {
    if (currentUser && (currentUser.role === 'admin' || currentUser.role === 'tester')) return true;
    if (!currentSubscription || currentSubscription.status !== 'active') return false;
    // All tiers now have access (with different limits) - checked via config
    return true;
}

function hasAccessToStrengthPhase(phase) {
    if (currentUser && (currentUser.role === 'admin' || currentUser.role === 'tester')) return true;
    if (!currentSubscription || currentSubscription.status !== 'active') return false;
    const tier = currentSubscription.tier;
    
    // Use centralized config function if available, otherwise fallback to original logic
    // Use the config function stored under a different name to avoid shadowing issues
    try {
        // Check if config is loaded
        if (window.TIER_ACCESS_CONFIG && window.TIER_ACCESS_CONFIG.features) {
            // Use the function stored under different name to avoid recursion
            const configFunc = window['hasAccessToStrengthPhaseConfig'];
            
            // Verify it's actually a function and has the right signature (takes 3 params: tier, phase, subscription)
            if (configFunc && typeof configFunc === 'function' && configFunc.length === 3) {
                // Call the config function with correct signature: (tier, phase, subscription)
                return configFunc(tier, phase, currentSubscription);
            }
        }
    } catch (e) {
        console.warn('Error calling config hasAccessToStrengthPhase, using fallback:', e);
        // Fall through to fallback logic
    }
    
    // Fallback to original logic if config not loaded
    if (phase === 1) {
        return tier === 'tier_one' || tier === 'tier_two' || tier === 'tier_three' || tier === 'tier_four' ||
               tier === 'daily' || tier === 'weekly' || tier === 'monthly';
    } else if (phase === 2) {
        return tier === 'tier_four' || tier === 'monthly';
    } else if (phase === 3) {
        return tier === 'tier_four' || tier === 'monthly';
    }
    return false;
}

function getRequiredTierForFeature(feature) {
    // Returns the minimum tier required for a feature
    switch(feature) {
        case 'coreFinishers':
            return 'tier_two';
        case 'strengthWorkouts':
            return 'tier_two';
        case 'strengthPhaseOne':
            return 'tier_two';
        case 'strengthPhaseTwo':
            return 'tier_three';
        case 'strengthPhaseThree':
            return 'tier_four';
        default:
            return null;
    }
}

