    paymentIcon.innerHTML = '💳';
    paymentIcon.style.cssText = 'font-size: 3.5rem; margin-bottom: 1rem;';
    
    // Title
    const title = document.createElement('h3');
    title.textContent = 'Payment Method Required';
    title.style.cssText = 'margin: 0 0 1rem 0; font-size: 1.5rem; color: #333; font-weight: 600;';
    
