// Global equipment list cache
let equipmentList = null;

// Load equipment list
async function loadEquipmentList() {
    // Only admins should ever hit the admin equipment API
    if (!token || !currentUser || currentUser.role !== 'admin') {
        return [];
    }

    if (equipmentList) {
        return equipmentList;
    }
    
    try {
        const response = await fetch(`${API_BASE}/admin/equipment`, {
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });
        
        if (response.ok) {
            const data = await response.json();
            equipmentList = data.equipment || [];
            return equipmentList;
        } else {
            console.error('Failed to load equipment:', response.status);
            return [];
        }
    } catch (error) {
        console.error('Error loading equipment:', error);
        return [];
    }
}

