// Handle workout form submission
async function handleWorkoutFormSubmit(form) {
    const submitBtn = form.querySelector('button[type="submit"]');
    const originalText = submitBtn.textContent;
    const errorDiv = document.getElementById('workoutFormError') || createErrorDiv(form);
    
    try {
        // Clear previous errors
        errorDiv.textContent = '';
        errorDiv.style.display = 'none';
        
        submitBtn.disabled = true;
        submitBtn.textContent = 'Validating form...';
        
        // Get workout type
        const workoutType = form.querySelector('#workoutType').value;
        if (!workoutType) {
            throw new Error('Please select a workout type');
        }
        
        // Get header (required for all types)
        const header = form.querySelector('#workoutHeader').value.trim();
        if (!header) {
            throw new Error('Please enter a header');
        }
        
        let formData = {
            workoutType: workoutType,
            header: header
        };
        
        // Collect data based on workout type
        if (workoutType === 'functional_fitness') {
            const date = form.querySelector('#workoutDate').value;
            const focusAreas = form.querySelector('#workoutFocusAreas').value.trim();
            
            if (!date) {
                throw new Error('Please select a date');
            }
            if (!focusAreas) {
                throw new Error('Please enter focus areas');
            }
            
            formData.date = date;
            formData.focusAreas = focusAreas;
            
            // Collect sub headers and exercises
            const subHeaders = [];
            const subHeaderSections = form.querySelectorAll('.sub-header-section');
            
            for (const section of subHeaderSections) {
                const subHeaderText = section.querySelector('[name="subHeader"]').value.trim().toUpperCase();
                if (!subHeaderText) continue;
                
                const exercises = [];
                const exerciseItems = section.querySelectorAll('.sub-header-exercise-item');
                
                for (const item of exerciseItems) {
                    const exerciseName = item.querySelector('[name="exerciseName"]').value.trim();
                    const exerciseId = item.querySelector('[name="exerciseId"]').value;
                    const equipmentSelect = item.querySelector('[name="exerciseEquipment"]');
                    const newEquipmentInput = item.querySelector('[name="newEquipmentName"]');
                    const sets = item.querySelector('[name="exerciseSets"]').value;
                    const reps = item.querySelector('[name="exerciseReps"]').value;
                    const repsType = item.querySelector('[name="exerciseRepsType"]').value;
                    
                    if (exerciseName) {
                        let equipmentId = null;
                        let newEquipmentName = null;
                        
                        // Handle equipment
                        if (equipmentSelect.value === '__NEW__' && newEquipmentInput) {
                            newEquipmentName = newEquipmentInput.value.trim();
                        } else if (equipmentSelect.value) {
                            equipmentId = parseInt(equipmentSelect.value);
                        }
                        
                        exercises.push({
                            exerciseName: exerciseName,
                            exerciseId: exerciseId || null,
                            equipmentId: equipmentId,
                            newEquipmentName: newEquipmentName,
                            sets: sets ? parseInt(sets) : null,
                            reps: reps ? parseInt(reps) : null,
                            repsType: repsType || null
                        });
                    }
                }
                
                if (exercises.length > 0) {
                    subHeaders.push({
                        subHeader: subHeaderText,
                        exercises: exercises
                    });
                }
            }
            
            if (subHeaders.length === 0) {
                throw new Error('Please add at least one sub header with exercises');
            }
            
            // Resolve exercise IDs and equipment IDs for functional fitness
            submitBtn.textContent = 'Resolving exercises and equipment...';
            for (const subHeader of subHeaders) {
                for (const exercise of subHeader.exercises) {
                    try {
                        // Create equipment if new
                        if (exercise.newEquipmentName) {
                            const equipResponse = await fetch(`${API_BASE}/admin/equipment`, {
                                method: 'POST',
                                headers: {
                                    'Content-Type': 'application/json',
                                    'Authorization': `Bearer ${token}`
                                },
                                body: JSON.stringify({
                                    name: exercise.newEquipmentName
                                })
                            });
                            
                            if (equipResponse.ok) {
                                const equipData = await equipResponse.json();
                                exercise.equipmentId = equipData.equipment.id;
                            }
                            delete exercise.newEquipmentName;
                        }
                        
                        // Resolve exercise ID
                        if (!exercise.exerciseId) {
                            const result = await resolveExerciseId(exercise.exerciseName, exercise.equipmentId);
                            if (result && result.id) {
                                exercise.exerciseId = result.id;
                            }
                        }
                        delete exercise.exerciseName; // Remove name, keep only ID
                    } catch (err) {
                        console.error(`Error resolving exercise "${exercise.exerciseName}":`, err);
                        throw err;
                    }
                }
            }
            
            formData.subHeaders = subHeaders;
            
        } else if (workoutType === 'core_finisher') {
            const date = form.querySelector('#workoutDate').value;
            
            if (!date) {
                throw new Error('Please select a date');
            }
            
            formData.date = date;
            
            // Collect sub headers and exercises
            const subHeaders = [];
            const subHeaderSections = form.querySelectorAll('.sub-header-section');
            
            for (const section of subHeaderSections) {
                const subHeaderText = section.querySelector('[name="subHeader"]').value.trim().toUpperCase();
                if (!subHeaderText) continue;
                
                const exercises = [];
                const exerciseItems = section.querySelectorAll('.sub-header-exercise-item');
                
                for (const item of exerciseItems) {
                    const exerciseName = item.querySelector('[name="exerciseName"]').value.trim();
                    const exerciseId = item.querySelector('[name="exerciseId"]').value;
                    const equipmentSelect = item.querySelector('[name="exerciseEquipment"]');
                    const newEquipmentInput = item.querySelector('[name="newEquipmentName"]');
                    const sets = item.querySelector('[name="exerciseSets"]').value;
                    const reps = item.querySelector('[name="exerciseReps"]').value;
                    const repsType = item.querySelector('[name="exerciseRepsType"]').value;
                    
                    if (exerciseName) {
                        let equipmentId = null;
                        let newEquipmentName = null;
                        
                        // Handle equipment
                        if (equipmentSelect.value === '__NEW__' && newEquipmentInput) {
                            newEquipmentName = newEquipmentInput.value.trim();
                        } else if (equipmentSelect.value) {
                            equipmentId = parseInt(equipmentSelect.value);
                        }
                        
                        exercises.push({
                            exerciseName: exerciseName,
                            exerciseId: exerciseId || null,
                            equipmentId: equipmentId,
                            newEquipmentName: newEquipmentName,
                            sets: sets ? parseInt(sets) : null,
                            reps: reps ? parseInt(reps) : null,
                            repsType: repsType || null
                        });
                    }
                }
                
                if (exercises.length > 0) {
                    subHeaders.push({
                        subHeader: subHeaderText,
                        exercises: exercises
                    });
                }
            }
            
            if (subHeaders.length === 0) {
                throw new Error('Please add at least one sub header with exercises');
            }
            
            // Resolve exercise IDs and equipment IDs for core finisher
            submitBtn.textContent = 'Resolving exercises and equipment...';
            for (const subHeader of subHeaders) {
                for (const exercise of subHeader.exercises) {
                    try {
                        // Create equipment if new
                        if (exercise.newEquipmentName) {
                            const equipResponse = await fetch(`${API_BASE}/admin/equipment`, {
                                method: 'POST',
                                headers: {
                                    'Content-Type': 'application/json',
                                    'Authorization': `Bearer ${token}`
                                },
                                body: JSON.stringify({
                                    name: exercise.newEquipmentName
                                })
                            });
                            
                            if (equipResponse.ok) {
                                const equipData = await equipResponse.json();
                                exercise.equipmentId = equipData.equipment.id;
                            }
                            delete exercise.newEquipmentName;
                        }
                        
                        // Resolve exercise ID
                        if (!exercise.exerciseId) {
                            const result = await resolveExerciseId(exercise.exerciseName, exercise.equipmentId);
                            if (result && result.id) {
                                exercise.exerciseId = result.id;
                            }
                        }
                        delete exercise.exerciseName; // Remove name, keep only ID
                    } catch (err) {
                        console.error(`Error resolving exercise "${exercise.exerciseName}":`, err);
                        throw err;
                    }
                }
            }
            
            formData.subHeaders = subHeaders;
            
        } else if (workoutType === 'strength') {
            // Strength workout - use existing block structure
            const phase = form.querySelector('#workoutPhase').value;
            const workoutName = form.querySelector('#workoutName').value.trim();
            
            if (!phase) {
                throw new Error('Please select a phase');
            }
            if (!workoutName) {
                throw new Error('Please enter a workout name');
            }
            
            formData.phase = phase;
            formData.name = workoutName;
            formData.primaryFocus = form.querySelector('#workoutPrimaryFocus').value.trim() || null;
            formData.secondaryFocus = form.querySelector('#workoutSecondaryFocus').value.trim() || null;
            formData.fmp = form.querySelector('#workoutFMP').value.trim() || null;
            formData.notes = form.querySelector('#workoutNotes').value.trim() || null;
            formData.blocks = [];
            
            // Collect blocks
            const blocks = form.querySelectorAll('.workout-block');
            let totalExercises = 0;
            
            for (const block of blocks) {
                const blockType = block.querySelector('[name="blockType"]').value;
                const blockTitle = block.querySelector('[name="blockTitle"]').value.trim() || null;
                const exercises = [];
                
                // Collect exercises with equipment
                const exerciseItems = block.querySelectorAll('.workout-exercise-item');
                for (const item of exerciseItems) {
                    const exerciseInput = item.querySelector('[name="exerciseName"]');
                    const equipmentSelect = item.querySelector('[name="exerciseEquipment"]');
                    const exerciseName = exerciseInput ? exerciseInput.value.trim() : '';
                    const equipmentId = equipmentSelect && equipmentSelect.value ? parseInt(equipmentSelect.value) : null;
                    
                    if (exerciseName) {
                        exercises.push({
                            exerciseName: exerciseName,
                            equipmentId: equipmentId
                        });
                        totalExercises++;
                    }
                }
                
                if (blockType && exercises.length > 0) {
                    formData.blocks.push({
                        blockType: blockType,
                        title: blockTitle,
                        exercises: exercises
                    });
                }
            }
            
            if (formData.blocks.length === 0) {
                throw new Error('Please add at least one block with exercises');
            }
            
            if (totalExercises === 0) {
                throw new Error('Please add at least one exercise to your blocks');
            }
            
            // Resolve exercise names to IDs for strength workouts
            submitBtn.textContent = `Resolving ${totalExercises} exercise(s)...`;
            const exerciseResults = {
                found: [],
                created: [],
                errors: []
            };
            
            for (const block of formData.blocks) {
                for (const exercise of block.exercises) {
                    try {
                        const result = await resolveExerciseId(exercise.exerciseName, exercise.equipmentId);
                        if (!result || !result.id) {
                            exerciseResults.errors.push(exercise.exerciseName);
                            throw new Error(`Failed to create or find exercise: ${exercise.exerciseName}`);
                        }
                        exercise.exerciseId = result.id;
                        if (result.created) {
                            exerciseResults.created.push(exercise.exerciseName);
                        } else {
                            exerciseResults.found.push(exercise.exerciseName);
                        }
                        delete exercise.exerciseName;
                        delete exercise.equipmentId;
                    } catch (err) {
                        console.error(`Error resolving exercise "${exercise.exerciseName}":`, err);
                        throw err;
                    }
                }
            }
        }
        
        // Submit workout to API
        submitBtn.textContent = 'Creating workout in database...';
        console.log('Submitting workout:', formData);
        
        const response = await fetch(`${API_BASE}/admin/workouts/create-unified`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify(formData)
        });
        
        const responseData = await response.json();
        
        if (!response.ok) {
            console.error('API Error Response:', responseData);
            throw new Error(responseData.error || `Server error (${response.status}): ${response.statusText}`);
        }
        
        console.log('Workout created successfully:', responseData);
        
        // Success message
        let successMessage = `✅ Workout Created Successfully!\n\n`;
        if (workoutType === 'functional_fitness') {
            successMessage += `Type: Functional Fitness\nDate: ${formData.date}\nFocus Areas: ${formData.focusAreas}\n`;
        } else if (workoutType === 'core_finisher') {
            successMessage += `Type: Core Finisher\nDate: ${formData.date}\n`;
        } else {
            successMessage += `Type: Strength Workout\nName: ${formData.name}\nPhase: ${formData.phase}\n`;
        }
        successMessage += `Header: ${header}\nWorkout ID: ${responseData.workoutId || responseData.id}\n`;
        
        alert(successMessage);
        
        // Reset form completely
        resetWorkoutForm(form);
        
    } catch (error) {
        console.error('Error submitting workout form:', error);
        const errorMessage = error.message || 'An unknown error occurred';
        errorDiv.textContent = `❌ Error: ${errorMessage}`;
        errorDiv.style.display = 'block';
        errorDiv.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    } finally {
        submitBtn.disabled = false;
        submitBtn.textContent = originalText;
    }
}

// Create error div if it doesn't exist
function createErrorDiv(form) {
    const errorDiv = document.createElement('div');
    errorDiv.id = 'workoutFormError';
    errorDiv.className = 'error-message';
    errorDiv.style.cssText = 'display: none; margin: 1rem 0; padding: 1rem; background: #f8d7da; border: 1px solid #dc3545; border-radius: 4px; color: #721c24;';
    form.insertBefore(errorDiv, form.firstChild);
    return errorDiv;
}

// Reset workout form completely
function resetWorkoutForm(form) {
    // Reset all form fields
    form.reset();
    
    // Reset workout type to trigger field visibility
    const workoutType = document.getElementById('workoutType');
    if (workoutType) {
        workoutType.value = '';
        handleWorkoutTypeChange('');
    }
    
    // Clear all sub headers
    const subHeadersContainer = document.getElementById('subHeadersContainer');
    if (subHeadersContainer) {
        subHeadersContainer.innerHTML = '';
    }
    
    // Clear all blocks
    const blocksContainer = document.getElementById('workoutBlocksContainer');
    if (blocksContainer) {
        blocksContainer.innerHTML = '';
    }
    
    // Clear date override warning
    const dateWarning = document.getElementById('dateOverrideWarning');
    if (dateWarning) {
        dateWarning.style.display = 'none';
    }
    
    // Clear error messages
    const errorDiv = document.getElementById('workoutFormError');
    if (errorDiv) {
        errorDiv.textContent = '';
        errorDiv.style.display = 'none';
    }
    
    // Reset counters
    if (typeof subHeaderCount !== 'undefined') subHeaderCount = 0;
    if (typeof blockCount !== 'undefined') blockCount = 0;
    
    // Scroll to top of form
    form.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

// Resolve exercise name to ID - search for existing or create new
// Returns: { id: number, created: boolean }
async function resolveExerciseId(exerciseName, equipmentId = null) {
    try {
        // First, try to find existing exercise
        const searchResponse = await fetch(`${API_BASE}/admin/exercises?search=${encodeURIComponent(exerciseName)}`, {
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });
        
        if (searchResponse.ok) {
            const searchData = await searchResponse.json();
            // Check for exact match (case-insensitive)
            const exactMatch = searchData.exercises.find(
                ex => ex.name.toLowerCase() === exerciseName.toLowerCase()
            );
            
            if (exactMatch) {
                console.log(`Found existing exercise: "${exerciseName}" (ID: ${exactMatch.id})`);
                
                // Link equipment if provided and not already linked
                if (equipmentId) {
                    // Equipment linking is handled by the API when creating/finding exercise
                    await fetch(`${API_BASE}/admin/exercises`, {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                            'Authorization': `Bearer ${token}`
                        },
                        body: JSON.stringify({
                            name: exerciseName,
                            equipmentId: equipmentId
                        })
                    }).catch(err => {
                        console.warn(`Could not link equipment to existing exercise:`, err);
                    });
                }
                
                return { id: exactMatch.id, created: false };
            }
        }
        
        // If not found, create new exercise with equipment
        console.log(`Creating new exercise: "${exerciseName}"${equipmentId ? ` with equipment ID ${equipmentId}` : ''}`);
        const createResponse = await fetch(`${API_BASE}/admin/exercises`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify({
                name: exerciseName,
                description: null,
                equipmentId: equipmentId
            })
        });
        
        if (!createResponse.ok) {
            const errorData = await createResponse.json().catch(() => ({ error: 'Unknown error' }));
            const errorMsg = errorData.error || `HTTP ${createResponse.status}: ${createResponse.statusText}`;
            console.error(`Failed to create exercise "${exerciseName}":`, errorMsg);
            throw new Error(`Failed to create exercise "${exerciseName}": ${errorMsg}`);
        }
        
        const createData = await createResponse.json();
        if (!createData.exercise || !createData.exercise.id) {
            throw new Error(`Invalid response when creating exercise "${exerciseName}"`);
        }
        
        console.log(`Created new exercise: "${exerciseName}" (ID: ${createData.exercise.id})`);
        return { id: createData.exercise.id, created: true };
        
    } catch (error) {
        console.error(`Error resolving exercise "${exerciseName}":`, error);
        throw error;
    }
}

