// Admin list caches for client-side searching
let adminUsersCache = [];
let adminUsersTesterMode = false;
let adminMembersRowsCache = [];

// Load all users for admin view (or just current user for testers)
async function loadAllUsers() {
    const container = document.getElementById('usersTableContainer');
    if (!container) return;
    
    container.innerHTML = '<p class="loading">Loading users...</p>';
    
    try {
        // For testers, only load their own user data
        if (currentUser && currentUser.role === 'tester') {
            // Double-check we have current user ID
            if (!currentUser.id) {
                container.innerHTML = '<p class="error-message">Unable to load user data</p>';
                return;
            }
            
            const response = await fetch(`${API_BASE}/auth/me`, {
                headers: {
                    'Authorization': `Bearer ${token}`
                }
            });
            
            if (response.ok) {
                const data = await response.json();
                // Ensure we only show the current user's data
                if (data.user && data.user.id === currentUser.id) {
                    // Format the user data to match the admin users structure
                    const userData = {
                        id: data.user.id,
                        email: data.user.email,
                        name: data.user.name || null,
                        role: data.user.role || 'user',
                        subscription_tier: data.subscription ? data.subscription.tier : null,
                        subscription_status: data.subscription ? data.subscription.status : null,
                        subscription_end: data.subscription ? data.subscription.end_date : null,
                        created_at: data.user.created_at
                    };
                    adminUsersCache = [userData];
                    adminUsersTesterMode = true;
                    renderUsersTable(adminUsersCache, adminUsersTesterMode);
                } else {
                    container.innerHTML = '<p class="error-message">Access denied</p>';
                }
            } else {
                container.innerHTML = '<p class="error-message">Failed to load user data</p>';
            }
        } else {
            // For admins, load all users
            const response = await fetch(`${API_BASE}/admin/users`, {
                headers: {
                    'Authorization': `Bearer ${token}`
                }
            });
            
            if (response.ok) {
                const data = await response.json();
                adminUsersCache = data.users || [];
                adminUsersTesterMode = false;
                renderUsersTable(adminUsersCache, adminUsersTesterMode);
            } else if (response.status === 403) {
                container.innerHTML = '<p class="error-message">Admin access required</p>';
            } else {
                container.innerHTML = '<p class="error-message">Failed to load users</p>';
            }
        }
    } catch (error) {
        console.error('Error loading users:', error);
        container.innerHTML = '<p class="error-message">Error loading users</p>';
    }
}

/** prod-test*@example.com automation accounts — hidden from admin Users tab (matches /admin/users). */
function isProdTestEmailUser(user) {
    if (!user) return false;
    const e = String(user.email || '').toLowerCase();
    return e.startsWith('prod-test') && e.endsWith('@example.com');
}

// Render users table
function renderUsersTable(users, isTesterMode = false) {
    const container = document.getElementById('usersTableContainer');
    if (!container) return;
    
    // For testers, filter to only show their own account
    let filteredUsers = users;
    if (isTesterMode && currentUser && currentUser.id) {
        filteredUsers = users.filter(user => {
            const userId = typeof user.id === 'number' ? user.id : parseInt(user.id);
            const currentUserId = typeof currentUser.id === 'number' ? currentUser.id : parseInt(currentUser.id);
            return userId === currentUserId;
        });
    } else if (!isTesterMode) {
        const sortKey = (u) => {
            if (u.last_login) return new Date(u.last_login).getTime();
            return u.created_at ? new Date(u.created_at).getTime() : 0;
        };
        filteredUsers = [...users].filter(u => !isProdTestEmailUser(u)).sort((a, b) => sortKey(b) - sortKey(a));
    }
    
    const usersSearchInput = document.getElementById('adminUsersSearchInput');
    const usersSearchQuery = String(usersSearchInput?.value || '').trim().toLowerCase();
    if (usersSearchQuery) {
        filteredUsers = filteredUsers.filter((u) => {
            const name = String(u.name || '').toLowerCase();
            const email = String(u.email || '').toLowerCase();
            const role = String(u.role || '').toLowerCase();
            const ip = String(u.last_login_ip || '').toLowerCase();
            return name.includes(usersSearchQuery)
                || email.includes(usersSearchQuery)
                || role.includes(usersSearchQuery)
                || ip.includes(usersSearchQuery);
        });
    }

    if (filteredUsers.length === 0) {
        container.innerHTML = '<p class="loading">No users found</p>';
        return;
    }

    const switchUserIconSvg = '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M7.5 21 3 16.5m0 0L7.5 12M3 16.5h13.5m0-13.5L21 7.5m0 0L16.5 12M21 7.5H7.5"/></svg>';
    
    const table = `
        <table class="users-table">
            <thead>
                <tr>
                    ${!isTesterMode ? `<th class="switch-user-col" scope="col" title="Switch user">${switchUserIconSvg}</th>` : ''}
                    <th>Name</th>
                    <th>Email</th>
                    <th>Role</th>
                    <th>IP Address</th>
                    <th>Last Login</th>
                    <th>Created</th>
                </tr>
            </thead>
            <tbody>
                ${filteredUsers.map(user => {
                    const lastLoginDate = user.last_login ? formatDateTimeMMDDYYYYHHMM(user.last_login) : 'Never';
                    const createdDate = user.created_at ? formatDateMMDDYYYY(user.created_at) : 'N/A';
                    const ipAddress = user.last_login_ip || 'N/A';
                    
                    // Role badge (editable) - consistent nested structure
                    // For testers, role is not editable (they can't change their own role)
                    const roleText = user.role === 'admin' ? 'Admin' : 
                                    user.role === 'tester' ? 'Tester' : 'User';
                    const roleBadge = isTesterMode ? 
                        `<span class="role-badge ${user.role || 'user'}">${roleText}</span>` :
                        `<span class="editable-badge role-badge ${user.role || 'user'}" data-field="role" data-user-id="${user.id}"><span class="role-badge ${user.role || 'user'}">${roleText}</span></span>`;
                    
                    // Created date with delete option (only for admins)
                    const createdCell = isTesterMode ? 
                        `<span class="created-date">${createdDate}</span>` :
                        `
                        <div class="created-cell">
                            <span class="created-date">${createdDate}</span>
                            <button class="delete-user-btn" data-user-id="${user.id}" data-user-email="${escapeHtml(user.email || '')}" title="Delete user">
                                🗑️
                            </button>
                        </div>
                    `;
                    
                    // Switch user button (admin only, don't show for the current user)
                    const switchUserButton = !isTesterMode && currentUser && currentUser.role === 'admin' && currentUser.id !== user.id ?
                        `<button type="button" class="switch-user-btn" data-user-id="${user.id}" data-user-email="${escapeHtml(user.email || '')}" title="Switch to view as this user" aria-label="Switch to view as this user">${switchUserIconSvg}</button>` :
                        '';
                    
                    return `
                        <tr>
                            ${!isTesterMode ? `<td class="switch-user-cell">${switchUserButton}</td>` : ''}
                            <td>${escapeHtml(user.name || 'N/A')}</td>
                            <td>${escapeHtml(user.email || '')}</td>
                            <td>${roleBadge}</td>
                            <td style="font-family: monospace; font-size: 0.875rem;">${escapeHtml(ipAddress)}</td>
                            <td>${lastLoginDate}</td>
                            <td>${createdCell}</td>
                        </tr>
                    `;
                }).join('')}
            </tbody>
        </table>
    `;
    
    container.innerHTML = table;
    
    // Add click handlers for editable badges
    container.querySelectorAll('.editable-badge').forEach(badge => {
        badge.addEventListener('click', handleBadgeEdit);
    });
    
    // Add delete button event listeners (only for admins)
    if (!isTesterMode) {
        container.querySelectorAll('.delete-user-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.stopPropagation();
                const userId = btn.dataset.userId;
                const userEmail = btn.dataset.userEmail;
                handleDeleteUser(userId, userEmail);
            });
        });
        
        // Add switch user button event listeners
        container.querySelectorAll('.switch-user-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.stopPropagation();
                const userId = parseInt(btn.dataset.userId);
                const userEmail = btn.dataset.userEmail;
                handleSwitchUser(userId, userEmail);
            });
        });
    }
}

async function handleGenerateTempLoginCode(emailOrOpts) {
    const isObj = emailOrOpts && typeof emailOrOpts === 'object' && !Array.isArray(emailOrOpts);
    const email = isObj ? (emailOrOpts.email || '') : String(emailOrOpts || '');
    const loginCodeRequestId = isObj ? emailOrOpts.loginCodeRequestId : null;
    if (!currentUser || currentUser.role !== 'admin') return;
    if (!loginCodeRequestId && !email) return;
    const authToken = localStorage.getItem('token');
    if (!authToken) {
        alert('Not logged in');
        return;
    }
    try {
        const body =
            loginCodeRequestId != null && Number.isFinite(Number(loginCodeRequestId)) && Number(loginCodeRequestId) > 0
                ? { login_code_request_id: Number(loginCodeRequestId) }
                : { email };
        const response = await fetch(`${API_BASE}/admin/users/temp-login-code`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${authToken}` },
            body: JSON.stringify(body)
        });
        const data = await response.json().catch(() => ({}));
        if (!response.ok) {
            const msgFromErrors = Array.isArray(data.errors)
                ? data.errors.map((e) => {
                    if (e.msg) return e.msg;
                    if (e.message) return e.message;
                    if (e.path && e.type) return `${e.path}: ${e.type}`;
                    return String(e);
                }).filter(Boolean).join('; ')
                : null;
            const msg = data.error || data.message || msgFromErrors || `Failed to generate temporary code (HTTP ${response.status})`;
            alert(msg);
            return;
        }
        const code = String(data.code || '').trim();
        const displayEmail = data.userEmail || email || '';
        let copied = false;
        if (code && navigator.clipboard && navigator.clipboard.writeText) {
            try {
                await navigator.clipboard.writeText(code);
                copied = true;
            } catch (clipErr) {
                console.warn('Clipboard copy skipped:', clipErr && clipErr.message);
            }
        }
        alert(
            `6-digit code generated for ${displayEmail}.\n\nCode: ${code}\nExpires: ${data.expiresAt ? new Date(data.expiresAt).toLocaleString() : 'in 24 hours'}\n\nTell member to log in with email + this code, then set a new password.` +
                (copied ? '\n\nCode copied to clipboard.' : '\n\n(Copy the code manually if needed.)')
        );
    } catch (e) {
        console.error('Generate temp code error:', e);
        const detail = e && e.message ? ` ${e.message}` : '';
        alert(`Failed to generate temporary code.${detail}`);
    }
}

// Handle switching to view as another user (admin only)
async function handleSwitchUser(targetUserId, targetUserEmail) {
    if (!currentUser || currentUser.role !== 'admin') {
        alert('Only admins can switch users');
        return;
    }

    // Confirm switch
    if (!confirm(`Switch to view as ${targetUserEmail}? You will see the application exactly as this user sees it.`)) {
        return;
    }

    try {
        const token = localStorage.getItem('token');
        const response = await fetch(`${API_BASE}/admin/switch-user`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify({
                targetUserId: targetUserId
            })
        });

        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(errorData.error || 'Failed to switch user');
        }

        const data = await response.json();
        
        // Store original admin info in sessionStorage
        sessionStorage.setItem('originalAdmin', JSON.stringify({
            id: data.originalAdmin.id,
            email: data.originalAdmin.email,
            name: data.originalAdmin.name,
            token: token // Store original admin token
        }));

        // Update token and user info
        localStorage.setItem('token', data.token);
        window.token = data.token;
        // Note: We don't need to reassign the top-level `token` variable
        // because we're reloading the page, which will read from localStorage
        currentUser = data.user;

        // Show banner indicating we're viewing as another user
        showUserSwitchBanner(data.user, data.originalAdmin);

        // Reload the page to show the user's view
        window.location.reload();
    } catch (error) {
        console.error('Error switching user:', error);
        alert(`Failed to switch user: ${error.message}`);
    }
}

// Show banner when viewing as another user
function showUserSwitchBanner(viewingAsUser, originalAdmin) {
    // Remove any existing banner
    const existingBanner = document.getElementById('userSwitchBanner');
    if (existingBanner) {
        existingBanner.remove();
    }

    const banner = document.createElement('div');
    banner.id = 'userSwitchBanner';
    banner.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        right: 0;
        background: #dc2626;
        color: white;
        padding: 0.75rem 1rem;
        text-align: center;
        z-index: 10002;
        display: flex;
        justify-content: center;
        align-items: center;
        gap: 1rem;
        box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
    `;

    banner.innerHTML = `
        <span style="font-weight: 600;">Viewing as: ${escapeHtml(viewingAsUser.email)}</span>
        <button id="switchBackBtn" style="padding: 0.5rem 1rem; background: white; color: #dc2626; border: none; border-radius: 4px; font-weight: 600; cursor: pointer; font-size: 0.875rem;">
            Switch Back to ${escapeHtml(originalAdmin.email)}
        </button>
    `;

    document.body.appendChild(banner);

    // Adjust body padding to account for banner
    document.body.style.paddingTop = '48px';

    // Add switch back handler
    document.getElementById('switchBackBtn').onclick = () => {
        switchBackToAdmin();
    };
}

// Switch back to original admin account
function switchBackToAdmin() {
    const originalAdminStr = sessionStorage.getItem('originalAdmin');
    if (!originalAdminStr) {
        alert('Unable to switch back. Please log out and log back in.');
        return;
    }

    const originalAdmin = JSON.parse(originalAdminStr);
    
    // Restore original admin token
    localStorage.setItem('token', originalAdmin.token);
    window.token = originalAdmin.token;
    token = originalAdmin.token;

    // Remove banner
    const banner = document.getElementById('userSwitchBanner');
    if (banner) {
        banner.remove();
    }
    document.body.style.paddingTop = '0';

    // Clear session storage
    sessionStorage.removeItem('originalAdmin');

    // Reload page
    window.location.reload();
}

// Check if we're viewing as another user on page load
function checkUserSwitchStatus() {
    const originalAdminStr = sessionStorage.getItem('originalAdmin');
    if (originalAdminStr && currentUser) {
        const originalAdmin = JSON.parse(originalAdminStr);
        // Only show banner if current user is not the original admin
        const currentUserId = typeof currentUser.id === 'number' ? currentUser.id : parseInt(currentUser.id);
        const originalAdminId = typeof originalAdmin.id === 'number' ? originalAdmin.id : parseInt(originalAdmin.id);
        if (currentUserId !== originalAdminId) {
            showUserSwitchBanner(currentUser, originalAdmin);
        } else {
            // If we're back to the original admin, clear the session storage
            sessionStorage.removeItem('originalAdmin');
        }
    }
}

// Track open editors to prevent multiple opens
let openEditorBadge = null;
let openEditorHandler = null;

// Handle badge editing
function handleBadgeEdit(e) {
    e.stopPropagation();
    e.preventDefault();
    
    const badge = e.currentTarget;
    
    // If clicking on an option button, don't handle
    if (e.target.closest('.badge-option') || e.target.closest('.badge-options') || e.target.closest('.badge-date-editor')) {
        return;
    }
    
    // If an editor is already open, close it first
    if (openEditorBadge && openEditorBadge !== badge) {
        if (openEditorHandler) {
            document.removeEventListener('click', openEditorHandler, true);
            openEditorHandler = null;
        }
        openEditorBadge = null;
    }
    
    // If clicking the same badge that's already open, close it
    if (openEditorBadge === badge) {
        const oldHTML = badge.dataset.oldHTML;
        if (oldHTML) {
            badge.innerHTML = oldHTML;
            badge.removeAttribute('data-old-html');
        }
        if (openEditorHandler) {
            document.removeEventListener('click', openEditorHandler, true);
            openEditorHandler = null;
        }
        openEditorBadge = null;
        return;
    }
    
    const field = badge.dataset.field;
    const userId = typeof badge.dataset.userId === 'string' ? parseInt(badge.dataset.userId) : badge.dataset.userId;
    const currentValue = badge.dataset.currentValue || badge.textContent.trim();
    
    // For testers, only allow editing their own account
    if (currentUser && currentUser.role === 'tester') {
        const currentUserId = typeof currentUser.id === 'number' ? currentUser.id : parseInt(currentUser.id);
        const badgeUserId = typeof userId === 'number' ? userId : parseInt(userId);
        
        if (badgeUserId !== currentUserId) {
            alert('You can only edit your own account.');
            loadAllUsers(); // Reload to reset
            return;
        }
        
        // For testers, don't allow role editing
        if (field === 'role') {
            alert('You cannot change your role.');
            loadAllUsers(); // Reload to reset
            return;
        }
    }
    
    if (field === 'role') {
        showRoleEditor(badge, userId, currentValue);
    } else if (field === 'tier') {
        showTierEditor(badge, userId, currentValue);
    } else if (field === 'status') {
        showStatusEditor(badge, userId, currentValue);
    } else if (field === 'end_date') {
        showExpirationEditor(badge, userId, currentValue);
    }
}

// Show role editor
function showRoleEditor(badge, userId, currentValue) {
    const roles = ['user', 'admin', 'tester'];
    const currentRole = badge.classList.contains('admin') ? 'admin' : 
                       badge.classList.contains('tester') ? 'tester' : 'user';
    
    const oldHTML = badge.innerHTML;
    badge.dataset.oldHTML = oldHTML;
    openEditorBadge = badge;
    
    // Track the initial touch event to prevent it from closing the editor
    let initialTouchTarget = null;
    const captureInitialTouch = (e) => {
        initialTouchTarget = e.target;
    };
    document.addEventListener('touchstart', captureInitialTouch, true);
    
    // Create options container
    const optionsContainer = document.createElement('div');
    optionsContainer.className = 'badge-options';
    
    // Function to position dropdown relative to badge
    const positionDropdown = () => {
        const badgeRect = badge.getBoundingClientRect();
        optionsContainer.style.position = 'fixed';
        optionsContainer.style.top = `${badgeRect.bottom + window.scrollY + 4}px`;
        optionsContainer.style.left = `${badgeRect.left + window.scrollX}px`;
        optionsContainer.style.zIndex = '99999';
    };
    
    roles.forEach(role => {
        const optionBtn = document.createElement('button');
        optionBtn.className = `badge-option ${role === currentRole ? 'active' : ''}`;
        optionBtn.textContent = role.charAt(0).toUpperCase() + role.slice(1);
        
        // Handle both click and touch events for better reliability
        const handleOptionSelect = (e) => {
            e.stopPropagation();
            e.preventDefault();
            if (openEditorHandler) {
                document.removeEventListener('click', openEditorHandler, true);
                document.removeEventListener('touchend', openEditorHandler, true);
                document.removeEventListener('touchstart', captureInitialTouch, true);
                window.removeEventListener('scroll', positionDropdown, true);
                window.removeEventListener('resize', positionDropdown);
                openEditorHandler = null;
            }
            // Remove dropdown from body
            if (optionsContainer.parentNode === document.body) {
                document.body.removeChild(optionsContainer);
            }
            openEditorBadge = null;
            if (role !== currentRole) {
                updateUserRole(userId, role, badge);
            } else {
                badge.innerHTML = oldHTML;
                badge.removeAttribute('data-old-html');
            }
        };
        
        optionBtn.addEventListener('click', handleOptionSelect);
        optionBtn.addEventListener('touchstart', (e) => {
            e.stopPropagation();
            optionBtn.classList.add('touch-active');
        });
        optionBtn.addEventListener('touchend', (e) => {
            e.stopPropagation();
            setTimeout(() => optionBtn.classList.remove('touch-active'), 150);
            handleOptionSelect(e);
        });
        
        optionsContainer.appendChild(optionBtn);
    });
    
    // Append to body and position
    document.body.appendChild(optionsContainer);
    positionDropdown();
    
    // Update position on scroll/resize
    window.addEventListener('scroll', positionDropdown, true);
    window.addEventListener('resize', positionDropdown);
    
    // Mark badge as having open editor (for visual feedback)
    badge.innerHTML = '<span class="role-badge ' + currentRole + '">' + (currentRole.charAt(0).toUpperCase() + currentRole.slice(1)) + '</span>';
    
    // Close on outside click/touch - use capture phase for better handling
    openEditorHandler = (e) => {
        // Check if the event target is within the badge or options container
        const target = e.target;
        const isWithinBadge = badge.contains(target);
        const isWithinOptions = optionsContainer.contains(target);
        
        // On mobile, ignore the initial touch event that opened the editor
        if (e.type === 'touchend' && initialTouchTarget && target === initialTouchTarget) {
            initialTouchTarget = null;
            return;
        }
        
        if (!isWithinBadge && !isWithinOptions) {
            badge.innerHTML = oldHTML;
            badge.removeAttribute('data-old-html');
            // Remove dropdown from body
            if (optionsContainer.parentNode === document.body) {
                document.body.removeChild(optionsContainer);
            }
            document.removeEventListener('click', openEditorHandler, true);
            document.removeEventListener('touchend', openEditorHandler, true);
            document.removeEventListener('touchstart', captureInitialTouch, true);
            window.removeEventListener('scroll', positionDropdown, true);
            window.removeEventListener('resize', positionDropdown);
            openEditorHandler = null;
            openEditorBadge = null;
            initialTouchTarget = null;
        }
    };
    // Use setTimeout with a delay to prevent the initial touch event from closing the editor
    setTimeout(() => {
        document.addEventListener('click', openEditorHandler, true);
        document.addEventListener('touchend', openEditorHandler, true);
        document.removeEventListener('touchstart', captureInitialTouch, true);
    }, 300);
}

