// Show status editor
function showStatusEditor(badge, userId, currentValue) {
    const statuses = ['Active', 'Canceled', 'Expired'];
    const currentStatus = currentValue ? currentValue.charAt(0).toUpperCase() + currentValue.slice(1) : 'None';
    
    const oldHTML = badge.innerHTML;
    badge.dataset.oldHTML = oldHTML;
    openEditorBadge = badge;
    
    // Track the initial touch event to prevent it from closing the editor
    let initialTouchTarget = null;
    const captureInitialTouch = (e) => {
        initialTouchTarget = e.target;
    };
    document.addEventListener('touchstart', captureInitialTouch, true);
    
    // Create options container
    const optionsContainer = document.createElement('div');
    optionsContainer.className = 'badge-options';
    
    // Function to position dropdown relative to badge
    const positionDropdown = () => {
        const badgeRect = badge.getBoundingClientRect();
        optionsContainer.style.position = 'fixed';
        optionsContainer.style.top = `${badgeRect.bottom + window.scrollY + 4}px`;
        optionsContainer.style.left = `${badgeRect.left + window.scrollX}px`;
        optionsContainer.style.zIndex = '99999';
    };
    
    statuses.forEach(status => {
        const optionBtn = document.createElement('button');
        optionBtn.className = `badge-option ${status === currentStatus ? 'active' : ''}`;
        optionBtn.textContent = status;
        
        // Handle both click and touch events for better reliability
        const handleOptionSelect = (e) => {
            e.stopPropagation();
            e.preventDefault();
            if (openEditorHandler) {
                document.removeEventListener('click', openEditorHandler, true);
                document.removeEventListener('touchend', openEditorHandler, true);
                document.removeEventListener('touchstart', captureInitialTouch, true);
                window.removeEventListener('scroll', positionDropdown, true);
                window.removeEventListener('resize', positionDropdown);
                openEditorHandler = null;
            }
            // Remove dropdown from body
            if (optionsContainer.parentNode === document.body) {
                document.body.removeChild(optionsContainer);
            }
            openEditorBadge = null;
            const statusValue = status.toLowerCase();
            if (statusValue !== (currentValue ? currentValue.toLowerCase() : '')) {
                updateSubscription(userId, { status: statusValue }, badge, 'status');
            } else {
                badge.innerHTML = oldHTML;
                badge.removeAttribute('data-old-html');
            }
        };
        
        optionBtn.addEventListener('click', handleOptionSelect);
        optionBtn.addEventListener('touchstart', (e) => {
            e.stopPropagation();
            optionBtn.classList.add('touch-active');
        });
        optionBtn.addEventListener('touchend', (e) => {
            e.stopPropagation();
            setTimeout(() => optionBtn.classList.remove('touch-active'), 150);
            handleOptionSelect(e);
        });
        
        optionsContainer.appendChild(optionBtn);
    });
    
    // Append to body and position
    document.body.appendChild(optionsContainer);
    positionDropdown();
    
    // Update position on scroll/resize
    window.addEventListener('scroll', positionDropdown, true);
    window.addEventListener('resize', positionDropdown);
    
    // Get current status badge HTML for display
    const statusBadgeClass = currentValue ? currentValue.toLowerCase() : 'none';
    badge.innerHTML = '<span class="status-badge ' + statusBadgeClass + '">' + currentStatus + '</span>';
    
    // Close on outside click/touch - use capture phase for better handling
    openEditorHandler = (e) => {
        // Check if the event target is within the badge or options container
        const target = e.target;
        const isWithinBadge = badge.contains(target);
        const isWithinOptions = optionsContainer.contains(target);
        
        // On mobile, ignore the initial touch event that opened the editor
        if (e.type === 'touchend' && initialTouchTarget && target === initialTouchTarget) {
            initialTouchTarget = null;
            return;
        }
        
        if (!isWithinBadge && !isWithinOptions) {
            badge.innerHTML = oldHTML;
            badge.removeAttribute('data-old-html');
            // Remove dropdown from body
            if (optionsContainer.parentNode === document.body) {
                document.body.removeChild(optionsContainer);
            }
            document.removeEventListener('click', openEditorHandler, true);
            document.removeEventListener('touchend', openEditorHandler, true);
            document.removeEventListener('touchstart', captureInitialTouch, true);
            window.removeEventListener('scroll', positionDropdown, true);
            window.removeEventListener('resize', positionDropdown);
            openEditorHandler = null;
            openEditorBadge = null;
            initialTouchTarget = null;
        }
    };
    // Use setTimeout with a delay to prevent the initial touch event from closing the editor
    setTimeout(() => {
        document.addEventListener('click', openEditorHandler, true);
        document.addEventListener('touchend', openEditorHandler, true);
        document.removeEventListener('touchstart', captureInitialTouch, true);
    }, 300);
}

// Format date as MMM DD, YYYY for My Account view (e.g. Feb 17, 2026) — always America/Denver
function formatDateMyAccount(dateInput) {
    if (!dateInput) return 'N/A';
    try {
        const date = new Date(dateInput);
        if (isNaN(date.getTime())) return 'N/A';
        if (date.getFullYear() >= 2099) return 'Never';
        return date.toLocaleDateString('en-US', {
            timeZone: 'America/Denver',
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        });
    } catch (e) {
        return 'N/A';
    }
}

/** contract.next_payment_due_date from API: next charge date (matches term start when first charge is still future). Prefer over Stripe current_period_end for display. */
function formatGymNextPaymentDueFromContract(membershipData) {
    const ymd = membershipData?.contract?.next_payment_due_date;
    if (!ymd) return null;
    const raw = String(ymd).trim().split('T')[0].split(' ')[0];
    if (!/^\d{4}-\d{2}-\d{2}$/.test(raw)) return null;
    const [y, m, d] = raw.split('-').map(Number);
    return formatDateMyAccount(new Date(y, m - 1, d));
}

// Format date to mm/dd/yyyy — calendar date in America/Denver (not browser local)
function formatDateMMDDYYYY(dateString) {
    if (!dateString) return 'N/A';
    try {
        const date = new Date(dateString);
        if (isNaN(date.getTime())) return 'N/A';
        if (date.getFullYear() >= 2099) {
            return 'Never';
        }
        return date.toLocaleDateString('en-US', {
            timeZone: 'America/Denver',
            year: 'numeric',
            month: '2-digit',
            day: '2-digit'
        });
    } catch (e) {
        return 'N/A';
    }
}

function formatDateTimeMMDDYYYYHHMM(dateString) {
    if (!dateString) return 'N/A';
    try {
        const date = new Date(dateString);
        if (isNaN(date.getTime())) return 'N/A';
        // Same format as Drop Ins: "Feb 15, 2026, 3:30 PM" in Mountain time
        return date.toLocaleString('en-US', { timeZone: 'America/Denver', year: 'numeric', month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit', hour12: true });
    } catch (e) {
        return 'N/A';
    }
}

// Show expiration editor
function showExpirationEditor(badge, userId, currentValue) {
    const oldHTML = badge.innerHTML;
    
    // Check if it's "Never" (2099 or later)
    let isNever = false;
    let dateValue = '';
    if (currentValue && currentValue !== 'N/A') {
        const date = new Date(currentValue);
        if (!isNaN(date.getTime()) && date.getFullYear() >= 2099) {
            isNever = true;
        } else if (!isNaN(date.getTime())) {
            dateValue = date.toISOString().split('T')[0];
        }
    }
    
    // Track the initial touch event to prevent it from closing the editor
    let initialTouchTarget = null;
    const captureInitialTouch = (e) => {
        initialTouchTarget = e.target;
    };
    document.addEventListener('touchstart', captureInitialTouch, true);
    
    // Create editor container
    const editorContainer = document.createElement('div');
    editorContainer.className = 'badge-date-editor';
    
    // Create "Never" button
    const neverBtn = document.createElement('button');
    neverBtn.className = `badge-option ${isNever ? 'active' : ''}`;
    neverBtn.textContent = 'Never';
    
    // Function to position dropdown relative to badge
    const positionDropdown = () => {
        const badgeRect = badge.getBoundingClientRect();
        editorContainer.style.position = 'fixed';
        editorContainer.style.top = `${badgeRect.bottom + window.scrollY + 4}px`;
        editorContainer.style.left = `${badgeRect.left + window.scrollX}px`;
        editorContainer.style.zIndex = '99999';
    };
    
    const cleanupEditor = () => {
        if (openEditorHandler) {
            document.removeEventListener('click', openEditorHandler, true);
            document.removeEventListener('touchend', openEditorHandler, true);
            document.removeEventListener('touchstart', captureInitialTouch, true);
            window.removeEventListener('scroll', positionDropdown, true);
            window.removeEventListener('resize', positionDropdown);
            openEditorHandler = null;
        }
        // Remove editor from body
        if (editorContainer.parentNode === document.body) {
            document.body.removeChild(editorContainer);
        }
        openEditorBadge = null;
    };
    
    const handleNeverSelect = (e) => {
        e.stopPropagation();
        e.preventDefault();
        cleanupEditor();
        const neverDate = '2099-12-31T23:59:59.999Z';
        updateSubscription(userId, { end_date: neverDate }, badge, 'end_date');
    };
    
    neverBtn.addEventListener('click', handleNeverSelect);
    neverBtn.addEventListener('touchstart', (e) => {
        e.stopPropagation();
        neverBtn.classList.add('touch-active');
    });
    neverBtn.addEventListener('touchend', (e) => {
        e.stopPropagation();
        setTimeout(() => neverBtn.classList.remove('touch-active'), 150);
        handleNeverSelect(e);
    });
    
    // Create date input
    const dateInput = document.createElement('input');
    dateInput.type = 'date';
    dateInput.className = 'badge-date-input';
    dateInput.value = dateValue;
    
    const saveDate = () => {
        const newDate = dateInput.value;
        if (newDate) {
            const formattedDate = newDate + 'T23:59:59.999Z';
            updateSubscription(userId, { end_date: formattedDate }, badge, 'end_date');
        } else {
            badge.innerHTML = oldHTML;
        }
        cleanupEditor();
    };
    
    dateInput.addEventListener('change', (e) => {
        e.stopPropagation();
        saveDate();
    });
    
    dateInput.addEventListener('blur', (e) => {
        e.stopPropagation();
        if (!dateInput.value) {
            badge.innerHTML = oldHTML;
            badge.removeAttribute('data-old-html');
            cleanupEditor();
        }
    });
    
    dateInput.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') {
            e.stopPropagation();
            badge.innerHTML = oldHTML;
            badge.removeAttribute('data-old-html');
            cleanupEditor();
        }
    });
    
    editorContainer.appendChild(neverBtn);
    editorContainer.appendChild(dateInput);
    
    // Append to body and position
    document.body.appendChild(editorContainer);
    positionDropdown();
    
    // Update position on scroll/resize
    window.addEventListener('scroll', positionDropdown, true);
    window.addEventListener('resize', positionDropdown);
    
    // Show current value in badge
    const currentDisplay = isNever ? 'Never' : (currentValue ? formatDateMMDDYYYY(currentValue) : 'N/A');
    badge.innerHTML = '<span>' + currentDisplay + '</span>';
    badge.dataset.oldHTML = oldHTML;
    openEditorBadge = badge;
    
    // Close on outside click/touch - use capture phase for better handling
    openEditorHandler = (e) => {
        // Check if the event target is within the badge or editor container
        const target = e.target;
        const isWithinBadge = badge.contains(target);
        const isWithinEditor = editorContainer.contains(target);
        
        // On mobile, ignore the initial touch event that opened the editor
        if (e.type === 'touchend' && initialTouchTarget && target === initialTouchTarget) {
            initialTouchTarget = null;
            return;
        }
        
        if (!isWithinBadge && !isWithinEditor) {
            badge.innerHTML = oldHTML;
            badge.removeAttribute('data-old-html');
            cleanupEditor();
            initialTouchTarget = null;
        }
    };
    // Use setTimeout with a delay to prevent the initial touch event from closing the editor
    setTimeout(() => {
        document.addEventListener('click', openEditorHandler, true);
        document.addEventListener('touchend', openEditorHandler, true);
        document.removeEventListener('touchstart', captureInitialTouch, true);
    }, 300);
}

// Update user role
async function updateUserRole(userId, role, badge) {
    // For testers, prevent all role updates
    if (currentUser && currentUser.role === 'tester') {
        const currentUserId = typeof currentUser.id === 'number' ? currentUser.id : parseInt(currentUser.id);
        const badgeUserId = typeof userId === 'number' ? userId : parseInt(userId);
        
        if (badgeUserId !== currentUserId) {
            alert('You can only edit your own account.');
            loadAllUsers(); // Reload to reset
            return;
        }
        
        alert('You cannot change your role.');
        loadAllUsers(); // Reload to reset
        return;
    }
    
    try {
        const response = await fetch(`${API_BASE}/admin/users/${userId}/role`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify({ role })
        });
        
        if (response.ok) {
            const roleNames = { admin: 'Admin', tester: 'Tester', user: 'User' };
            badge.className = `editable-badge role-badge ${role}`;
            badge.innerHTML = `<span class="role-badge ${role}">${roleNames[role]}</span>`;
            badge.dataset.currentValue = role;
            // Re-attach click handler
            badge.addEventListener('click', handleBadgeEdit);
        } else {
            const error = await response.json();
            alert('Failed to update role: ' + (error.error || 'Unknown error'));
            loadAllUsers(); // Reload to reset
        }
    } catch (error) {
        console.error('Error updating role:', error);
        alert('Error updating role');
        loadAllUsers(); // Reload to reset
    }
}

// Delete user
async function deleteUser(userId) {
    // For testers, prevent all user deletions
    if (currentUser && currentUser.role === 'tester') {
        alert('You do not have permission to delete users.');
        return;
    }
    
    try {
        const response = await fetch(`${API_BASE}/admin/users/${userId}`, {
            method: 'DELETE',
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });
        
        if (response.ok) {
            // Reload users table
            loadAllUsers();
        } else {
            const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
            console.error('Delete user failed:', errorData);
            alert('Failed to delete user: ' + (errorData.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Error deleting user:', error);
        alert('Error deleting user: ' + error.message);
    }
}

// Handle delete user with confirmation
function handleDeleteUser(userId, userEmail) {
    const confirmed = confirm(`Are you sure you want to delete user "${userEmail}"?\n\nThis action cannot be undone and will delete all associated subscriptions and payments.`);
    if (confirmed) {
        deleteUser(userId);
    }
}

// Update subscription
async function updateSubscription(userId, updates, badge, field) {
    // For testers, only allow updating their own account
    if (currentUser && currentUser.role === 'tester') {
        const currentUserId = typeof currentUser.id === 'number' ? currentUser.id : parseInt(currentUser.id);
        const badgeUserId = typeof userId === 'number' ? userId : parseInt(userId);
        
        if (badgeUserId !== currentUserId) {
            alert('You can only edit your own account.');
            loadAllUsers(); // Reload to reset
            return;
        }
    }
    
    try {
        // Don't send empty updates
        const cleanUpdates = {};
        Object.keys(updates).forEach(key => {
            if (updates[key] !== undefined && updates[key] !== null && updates[key] !== '') {
                cleanUpdates[key] = updates[key];
            }
        });

        if (Object.keys(cleanUpdates).length === 0) {
            console.log('No valid updates to send');
            return;
        }

        console.log('Updating subscription for user', userId, 'with updates:', cleanUpdates);
        
        const response = await fetch(`${API_BASE}/admin/users/${userId}/subscription`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify(cleanUpdates)
        });
        
        if (response.ok) {
            // Reload users to get updated data from server
            loadAllUsers();
        } else {
            const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
            console.error('Update subscription failed:', errorData);
            alert('Failed to update subscription: ' + (errorData.error || errorData.errors?.[0]?.msg || 'Unknown error'));
            loadAllUsers(); // Reload to reset
        }
    } catch (error) {
        console.error('Error updating subscription:', error);
        alert('Error updating subscription: ' + error.message);
        loadAllUsers(); // Reload to reset
    }
}

