// Tab switching
function switchTab(tab) {
    document.querySelectorAll('.tab-btn').forEach(btn => {
        btn.classList.remove('active');
    });
    document.querySelector(`[data-tab="${tab}"]`).classList.add('active');

    if (tab === 'login') {
        document.getElementById('loginForm').style.display = 'flex';
        document.getElementById('registerForm').style.display = 'none';
        const tempForm = document.getElementById('tempPasswordChangeForm');
        if (tempForm) tempForm.style.display = 'none';
    } else {
        document.getElementById('loginForm').style.display = 'none';
        document.getElementById('registerForm').style.display = 'flex';
        const tempForm = document.getElementById('tempPasswordChangeForm');
        if (tempForm) tempForm.style.display = 'none';
    }
}

// Show auth section
function showAuthSection() {
    document.getElementById('authSection').style.display = 'block';
    document.getElementById('dashboardSection').style.display = 'none';
    document.getElementById('userInfo').style.display = 'none';
    document.getElementById('logoutBtn').style.display = 'none';
    // Reset to show Google OAuth first (hide email/password form)
    const googleAuthSection = document.getElementById('googleAuthSection');
    const emailPasswordSection = document.getElementById('emailPasswordSection');
    if (googleAuthSection) {
        googleAuthSection.style.display = 'block';
    }
    if (emailPasswordSection) {
        emailPasswordSection.style.display = 'none';
    }
    currentUser = null;
    currentSubscription = null;
    if (dateTimeInterval) {
        clearInterval(dateTimeInterval);
        dateTimeInterval = null;
    }
}

// Show dashboard
function showDashboard() {
    document.getElementById('authSection').style.display = 'none';
    document.getElementById('dashboardSection').style.display = 'block';
    document.getElementById('userInfo').style.display = 'flex';
    document.getElementById('logoutBtn').style.display = 'block';
    updateDateTime();
    // Update date/time every second
    if (dateTimeInterval) {
        clearInterval(dateTimeInterval);
    }
    dateTimeInterval = setInterval(updateDateTime, 1000);
    
    // Initially show only the dashboard card, hide other sections
    showOnlyDashboard();
}

// Show only the dashboard card, hide other sections
function showOnlyDashboard() {
    const subscriptionCard = document.querySelector('.subscription-card');
    const todayWorkoutCard = document.querySelector('.today-workout-card');
    const workoutsCard = document.querySelector('.workouts-card');
    const strengthWorkoutsCard = document.querySelector('.strength-workouts-card');
    const dashboardCard = document.querySelector('.dashboard-card');
    
    // For first-time users (no subscription), show ONLY subscription card (hide dashboard)
    const isFirstTimeUser = !currentSubscription;
    
    if (isFirstTimeUser) {
        // First-time user: Show subscription card and gym card (for drop-in option)
        if (subscriptionCard) subscriptionCard.style.display = 'block';
        if (dashboardCard) dashboardCard.style.display = 'none';
        if (todayWorkoutCard) todayWorkoutCard.style.display = 'none';
        if (workoutsCard) workoutsCard.style.display = 'none';
        if (strengthWorkoutsCard) strengthWorkoutsCard.style.display = 'none';
        const gymMembershipCard = document.querySelector('.gym-membership-card');
        if (gymMembershipCard) gymMembershipCard.style.display = 'block';
        
        // Hide dashboard instructions and toggle button
        const dashboardInstructions = document.querySelector('.dashboard-instructions');
        if (dashboardInstructions) {
            dashboardInstructions.style.display = 'none';
        }
        const toggleBtn = document.getElementById('dashboardToggleBtn');
        if (toggleBtn) {
            toggleBtn.style.display = 'none';
        }
    } else {
        // User has subscription: Show dashboard, hide subscription card
        if (subscriptionCard) subscriptionCard.style.display = 'none';
        const gymMembershipCard = document.querySelector('.gym-membership-card');
        if (gymMembershipCard) gymMembershipCard.style.display = 'none';
        if (dashboardCard) dashboardCard.style.display = 'block';
        if (todayWorkoutCard) todayWorkoutCard.style.display = 'none';
        if (workoutsCard) workoutsCard.style.display = 'none';
        if (strengthWorkoutsCard) strengthWorkoutsCard.style.display = 'none';
        
        // Expand dashboard items when showing only dashboard
        expandDashboardItems();
        const toggleBtn = document.getElementById('dashboardToggleBtn');
        if (toggleBtn) {
            toggleBtn.style.display = 'none';
        }
        // Show help section when on dashboard-only view
        const dashboardInstructions = document.querySelector('.dashboard-instructions');
        if (dashboardInstructions) {
            dashboardInstructions.style.display = 'block';
        }
    }
}

