// Handle login
async function handleLogin(e) {
    e.preventDefault();
    const email = document.getElementById('loginEmail').value;
    const password = document.getElementById('loginPassword').value;
    const errorDiv = document.getElementById('loginError');

    showLoading(true);
    errorDiv.classList.remove('show');

    try {
        const response = await fetch(`${API_BASE}/auth/login`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ email, password })
        });

        const data = await response.json();

        if (response.ok) {
            if (data.requiresPasswordChange) {
                pendingTempLogin = {
                    email: (data.email || email || '').trim(),
                    tempCode: password.trim()
                };
                document.getElementById('emailPasswordSection').style.display = 'block';
                document.getElementById('googleAuthSection').style.display = 'none';
                document.getElementById('loginForm').style.display = 'none';
                document.getElementById('registerForm').style.display = 'none';
                document.getElementById('forgotPasswordForm').style.display = 'none';
                document.getElementById('resetPasswordForm').style.display = 'none';
                document.getElementById('tempPasswordChangeForm').style.display = 'flex';
                const changeErr = document.getElementById('tempPasswordChangeError');
                if (changeErr) changeErr.classList.remove('show');
                return;
            }
            token = data.token;
            window.token = token; // Update global
            localStorage.setItem('token', token);
            currentUser = data.user || { email: email };
            
            // Force hard refresh to ensure latest code is loaded
            // Always send the user to the app dashboard base URL,
            // not back to whatever page they logged in from.
            const url = new URL(getAppBaseUrl());
            url.searchParams.set('_refresh', Date.now().toString());
            window.location.href = url.toString();
            return; // Exit early since we're reloading
        } else {
            errorDiv.textContent = data.error || 'Login failed';
            errorDiv.classList.add('show');
        }
    } catch (error) {
        errorDiv.textContent = 'Network error. Please try again.';
        errorDiv.classList.add('show');
    } finally {
        showLoading(false);
    }
}

async function handleTempPasswordChange(e) {
    e.preventDefault();
    const errorDiv = document.getElementById('tempPasswordChangeError');
    const newPassword = document.getElementById('tempNewPassword').value;
    const confirmPassword = document.getElementById('tempNewPasswordConfirm').value;
    errorDiv.classList.remove('show');

    if (!pendingTempLogin || !pendingTempLogin.email || !pendingTempLogin.tempCode) {
        errorDiv.textContent = 'Session expired. Please log in again with your temporary code.';
        errorDiv.classList.add('show');
        return;
    }
    if (newPassword !== confirmPassword) {
        errorDiv.textContent = 'Passwords do not match';
        errorDiv.classList.add('show');
        return;
    }
    if (!newPassword || newPassword.length < 6) {
        errorDiv.textContent = 'Password must be at least 6 characters';
        errorDiv.classList.add('show');
        return;
    }

    showLoading(true);
    try {
        const response = await fetch(`${API_BASE}/auth/complete-temp-login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                email: pendingTempLogin.email,
                tempCode: pendingTempLogin.tempCode,
                newPassword
            })
        });
        const data = await response.json().catch(() => ({}));
        if (!response.ok) {
            errorDiv.textContent = data.error || 'Failed to set password';
            errorDiv.classList.add('show');
            return;
        }
        pendingTempLogin = null;
        token = data.token;
        window.token = token;
        localStorage.setItem('token', token);
        currentUser = data.user || { email: data.email };
        const url = new URL(getAppBaseUrl());
        url.searchParams.set('_refresh', Date.now().toString());
        window.location.href = url.toString();
    } catch (error) {
        errorDiv.textContent = 'Network error. Please try again.';
        errorDiv.classList.add('show');
    } finally {
        showLoading(false);
    }
}

// Handle register
async function handleRegister(e) {
    e.preventDefault();
    const email = document.getElementById('registerEmail').value;
    const password = document.getElementById('registerPassword').value;
    const passwordConfirm = document.getElementById('registerPasswordConfirm').value;
    const errorDiv = document.getElementById('registerError');

    showLoading(true);
    errorDiv.classList.remove('show');

    // Validate passwords match
    if (password !== passwordConfirm) {
        errorDiv.textContent = 'Passwords do not match';
        errorDiv.classList.add('show');
        showLoading(false);
        return;
    }

    // Validate password length
    if (password.length < 6) {
        errorDiv.textContent = 'Password must be at least 6 characters';
        errorDiv.classList.add('show');
        showLoading(false);
        return;
    }

    try {
        const response = await fetch(`${API_BASE}/auth/register`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ email, password })
        });

        const data = await response.json();

        if (response.ok) {
            token = data.token;
            window.token = token; // Update global
            localStorage.setItem('token', token);
            currentUser = data.user || { email: email };
            
            // Ensure Stripe is initialized before showing dashboard
            if (!stripe) {
                console.log('Initializing Stripe after registration...');
                await initStripe();
            }
            
            showDashboard();
            updateUserInfo();
            setupAdminTab(); // Setup admin tab if user is admin
            // Load subscription first, then workouts (to ensure subscription status is available)
            loadSubscription().then(() => {
                loadWorkouts();
                // Ensure only dashboard is shown after data loads (or subscription card for first-time users)
                showOnlyDashboard();
                loadGymMembershipDetails();
            });
        } else {
            errorDiv.textContent = data.error || 'Registration failed';
            errorDiv.classList.add('show');
        }
    } catch (error) {
        errorDiv.textContent = 'Network error. Please try again.';
        errorDiv.classList.add('show');
    } finally {
        showLoading(false);
    }
}

// Check if reset token is in URL (or sessionStorage after a reload)
function checkResetToken() {
    const urlParams = new URLSearchParams(window.location.search);
    let resetToken = urlParams.get('token');
    // Fallback: may have been saved to sessionStorage before URL was stripped (e.g. by a reload)
    if (!resetToken) {
        try { resetToken = sessionStorage.getItem('password_reset_token'); } catch (e) {}
    }
    if (!resetToken) return;
    // Password reset tokens are 64 hex chars; ignore JWT-shaped tokens
    if (resetToken.length !== 64 || !/^[a-f0-9]+$/i.test(resetToken)) return;

    // Persist so a reload (e.g. _refresh) doesn't lose the token
    try { sessionStorage.setItem('password_reset_token', resetToken); } catch (e) {}
    // Show reset password form
    document.getElementById('emailPasswordSection').style.display = 'block';
    document.getElementById('googleAuthSection').style.display = 'none';
    document.getElementById('loginForm').style.display = 'none';
    document.getElementById('registerForm').style.display = 'none';
    document.getElementById('forgotPasswordForm').style.display = 'none';
    document.getElementById('resetPasswordForm').style.display = 'flex';
    document.getElementById('tempPasswordChangeForm').style.display = 'none';
    document.getElementById('resetPasswordForm').dataset.token = resetToken;
    // Clean URL only after we've saved token to sessionStorage
    window.history.replaceState({}, document.title, window.location.pathname);
}

