// Handle reset password
async function handleResetPassword(e) {
    e.preventDefault();
    const token = document.getElementById('resetPasswordForm').dataset.token;
    const password = document.getElementById('resetPassword').value;
    const passwordConfirm = document.getElementById('resetPasswordConfirm').value;
    const errorDiv = document.getElementById('resetPasswordError');
    const successDiv = document.getElementById('resetPasswordSuccess');

    if (!token) {
        errorDiv.textContent = 'Invalid reset token. Please request a new password reset.';
        errorDiv.classList.add('show');
        return;
    }

    // Validate passwords match
    if (password !== passwordConfirm) {
        errorDiv.textContent = 'Passwords do not match';
        errorDiv.classList.add('show');
        return;
    }

    // Validate password length
    if (password.length < 6) {
        errorDiv.textContent = 'Password must be at least 6 characters';
        errorDiv.classList.add('show');
        return;
    }

    showLoading(true);
    errorDiv.classList.remove('show');
    successDiv.style.display = 'none';

    try {
        const response = await fetch(`${API_BASE}/auth/reset-password`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ token, password })
        });

        const data = await response.json();

        if (response.ok) {
            successDiv.textContent = data.message || 'Password reset successful! You can now login with your new password.';
            successDiv.style.display = 'block';
            try { sessionStorage.removeItem('password_reset_token'); } catch (e) {}
            // Redirect to login after 2 seconds
            setTimeout(() => {
                document.getElementById('resetPasswordForm').style.display = 'none';
                document.getElementById('loginForm').style.display = 'flex';
                document.getElementById('resetPasswordForm').dataset.token = '';
            }, 2000);
        } else {
            errorDiv.textContent = data.error || 'Failed to reset password';
            errorDiv.classList.add('show');
        }
    } catch (error) {
        errorDiv.textContent = 'Network error. Please try again.';
        errorDiv.classList.add('show');
    } finally {
        showLoading(false);
    }
}

// Handle logout
function handleLogout() {
    localStorage.removeItem('token');
    token = null;
    window.token = null; // Update global
    // Force user back to public home page (not in-app Google sign-in)
    window.location.href = 'https://stoic-fit.com/home.html';
}

// Load subscription status
async function loadSubscription() {
    try {
        console.log('[loadSubscription] Fetching subscription from API...');
        const response = await fetch(`${API_BASE}/subscriptions/me`, {
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });

        console.log('[loadSubscription] Response status:', response.status);
        const data = await response.json();
        console.log('[loadSubscription] Response data:', JSON.stringify(data, null, 2));

        if (data.subscription) {
            const previousSubscription = currentSubscription;
            currentSubscription = data.subscription;
            
            // If payment method was just added (status improved), clear dismissed flag
            if (previousSubscription && 
                (previousSubscription.needs_payment || previousSubscription.has_payment_method === false) &&
                !currentSubscription.needs_payment && 
                currentSubscription.has_payment_method !== false) {
                sessionStorage.removeItem('paymentModalDismissed');
            }
            
            // Check and show payment modal
            checkAndShowPaymentModal();
        } else {
            currentSubscription = null;
            window.upgradeOptions = [];
        }

        renderSubscriptionStatus();
        updateUserInfo();
        updateTabLockStatus();
    } catch (error) {
        console.error('Failed to load subscription:', error);
        // Do not clear currentSubscription — keep /auth/me or prior payload so UI does not revert to wrong tier/banner
        renderSubscriptionStatus();
        updateUserInfo();
        updateTabLockStatus();
    }
}

// Handle subscription cancellation - show modal similar to downgrade
async function handleCancelSubscription(e) {
    e.preventDefault();
    
    if (!currentSubscription || currentSubscription.status !== 'active') {
        alert('No active subscription to cancel.');
        return;
    }
    
    const modal = document.getElementById('paymentModal');
    const errorDiv = document.getElementById('paymentError');
    const paymentElementContainer = document.getElementById('paymentElement');
    const submitBtn = document.getElementById('payButton');
    const modalContent = modal?.querySelector('.modal-content');
    const modalTitle = modalContent?.querySelector('h2'); // Get the "Complete Payment" h2
    
    if (!modal || !errorDiv || !paymentElementContainer || !submitBtn) {
        console.error('Missing payment modal elements:', {
            modal: !!modal,
            errorDiv: !!errorDiv,
            paymentElementContainer: !!paymentElementContainer,
            submitBtn: !!submitBtn
        });
        alert('Error: Payment modal elements not found. Please refresh the page and try again.');
        return;
    }
    
    // Hide the "Complete Payment" title when canceling
    if (modalTitle) {
        modalTitle.style.display = 'none';
    }
    
    // Clear any existing content
    paymentElementContainer.innerHTML = '';
    errorDiv.classList.remove('show');
    errorDiv.textContent = '';
    
    // Show the modal
    modal.style.display = 'block';
    
    // Calculate end date
    let endDate = 'the end date';
    if (currentSubscription.end_date) {
        endDate = formatDateMyAccount(currentSubscription.end_date);
    }
    
    // Show cancellation message instead of payment form
    paymentElementContainer.innerHTML = `
        <div style="padding: 0.5rem; text-align: center; width: 100%; max-width: 100%; box-sizing: border-box; overflow-x: hidden; word-wrap: break-word; overflow-wrap: break-word; min-width: 0;">
            <h3 style="margin-bottom: 0.5rem; color: #333; font-size: 0.9375rem; word-wrap: break-word; overflow-wrap: break-word; max-width: 100%;">Cancel Subscription</h3>
            <p style="margin-bottom: 0.5rem; color: #666; line-height: 1.4; font-size: 0.75rem; word-wrap: break-word; overflow-wrap: break-word; max-width: 100%;">
                Are you sure you want to cancel your subscription?
            </p>
            <div style="background: #fff3cd; border: 1px solid #ffc107; border-radius: 6px; padding: 0.5rem; margin-bottom: 0.5rem; width: 100%; max-width: 100%; box-sizing: border-box; overflow-x: hidden; word-wrap: break-word; overflow-wrap: break-word; min-width: 0;">
                <p style="margin: 0; color: #856404; font-weight: 500; font-size: 0.75rem; line-height: 1.3; word-wrap: break-word; overflow-wrap: break-word; max-width: 100%;">
                    Your subscription will remain active until <strong>${endDate}</strong>, but it will not renew automatically.
                </p>
            </div>
            <p style="margin: 0; color: #666; font-size: 0.6875rem; word-wrap: break-word; overflow-wrap: break-word; max-width: 100%;">
                Click "Confirm Cancellation" below to proceed.
            </p>
        </div>
    `;
    
    // Update submit button text, handler, and styling to match warning colors
    submitBtn.textContent = 'Confirm Cancellation';
    submitBtn.className = 'btn btn-cancel';
    submitBtn.onclick = async function() {
        await submitCancelSubscription();
    };
}

// Submit cancellation to backend
async function submitCancelSubscription() {
    const errorDiv = document.getElementById('paymentError');
    const submitBtn = document.getElementById('payButton');
    const modal = document.getElementById('paymentModal');
    const modalContent = modal?.querySelector('.modal-content');
    const modalTitle = modalContent?.querySelector('h2');
    
    if (!errorDiv || !submitBtn) {
        alert('Error: Payment elements not found');
        return;
    }
    
    errorDiv.classList.remove('show');
    errorDiv.textContent = '';
    submitBtn.disabled = true;
    submitBtn.textContent = 'Processing...';
    
    try {
        const response = await fetch(`${API_BASE}/subscriptions/cancel`, {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
            }
        });

        const data = await response.json();

        if (response.ok) {
            // Restore the "Complete Payment" title and button class before closing
            if (modalTitle) {
                modalTitle.style.display = 'block';
            }
            submitBtn.className = 'btn btn-primary';
            closePaymentModal();
            showSuccess('Subscription canceled successfully. Your subscription will remain active until the end date.');
            await loadSubscription();
            await loadWorkouts();
            renderSubscriptionStatus();
            showOnlyDashboard();
        } else {
            errorDiv.textContent = data.error || 'Failed to cancel subscription. Please try again.';
            errorDiv.classList.add('show');
            submitBtn.disabled = false;
            submitBtn.textContent = 'Confirm Cancellation';
        }
    } catch (error) {
        console.error('Failed to cancel subscription:', error);
        errorDiv.textContent = 'Failed to cancel subscription. Please try again.';
        errorDiv.classList.add('show');
        submitBtn.disabled = false;
        submitBtn.textContent = 'Confirm Cancellation';
    }
}

