// Determine if a tier change is an upgrade or downgrade
window.isUpgrade = function(currentTier, targetTier) {
    if (!currentTier || !targetTier) return false;
    const currentOrder = TIER_INFO[currentTier]?.order || 0;
    const targetOrder = TIER_INFO[targetTier]?.order || 0;
    return targetOrder > currentOrder;
};

window.isDowngrade = function(currentTier, targetTier) {
    if (!currentTier || !targetTier) return false;
    const currentOrder = TIER_INFO[currentTier]?.order || 0;
    const targetOrder = TIER_INFO[targetTier]?.order || 0;
    return targetOrder < currentOrder;
};

/** DB statuses that still grant app access (matches server getUserActiveSubscription). */
function subscriptionStatusGrantsAccess(status) {
    return status === 'active' || status === 'grace_period' || status === 'free_trial';
}

// Determine if tier_one should be shown to the user
// Tier one should only be hidden for users that have already had tier one (and it expired)
// or they have already moved up to a higher tier
function shouldShowTierOne(subscription) {
    // New users with no subscription can select tier_one
    if (!subscription) {
        return true;
    }
    
    // If user has expired tier_one, hide it (they already used it)
    if (subscription.tier === 'tier_one' && !subscriptionStatusGrantsAccess(subscription.status)) {
        return false;
    }
    
    // If user has any higher tier (even if expired), hide tier_one (they've moved up)
    const higherTiers = ['tier_two', 'tier_three', 'tier_four'];
    if (higherTiers.includes(subscription.tier)) {
        return false;
    }
    
    // If user has active tier_one, they already have it (but we could still show it as "current")
    // Actually, for selection purposes, we don't need to show it since they already have it
    if (subscription.tier === 'tier_one' && subscriptionStatusGrantsAccess(subscription.status)) {
        return false;
    }
    
    // Default: show tier_one for new users or edge cases
    return true;
}

// Show subscription info when Gym Membership is clicked
// Track if we're in subscription view mode
let isSubscriptionViewMode = false;

function showSubscriptionInfo() {
    // Set flag to indicate we're in subscription view mode
    isSubscriptionViewMode = true;
    
    // Hide all content sections
    const workoutContent = document.getElementById('todayWorkoutContent');
    const coreContent = document.getElementById('coreContent');
    const strengthContent = document.getElementById('strengthContent');
    const macroContent = document.getElementById('macroContent');
    const adminContent = document.getElementById('adminContent');
    const personalTrainerContent = document.getElementById('personalTrainerContent');
    const personalStrengthCoachContent = document.getElementById('personalStrengthCoachContent');
    
    if (workoutContent) workoutContent.style.display = 'none';
    if (coreContent) coreContent.style.display = 'none';
    if (strengthContent) strengthContent.style.display = 'none';
    if (macroContent) macroContent.style.display = 'none';
    if (adminContent) adminContent.style.display = 'none';
    if (personalTrainerContent) personalTrainerContent.style.display = 'none';
    if (personalStrengthCoachContent) personalStrengthCoachContent.style.display = 'none';
    
    // Hide all tabs
    const workoutTab = document.getElementById('workoutTab');
    const coreTab = document.getElementById('coreTab');
    const strengthTab = document.getElementById('strengthTab');
    const macroTab = document.getElementById('macroTab');
    const adminTab = document.getElementById('adminTab');
    
    if (workoutTab) workoutTab.classList.remove('active');
    if (coreTab) coreTab.classList.remove('active');
    if (strengthTab) strengthTab.classList.remove('active');
    if (macroTab) macroTab.classList.remove('active');
    if (adminTab) adminTab.classList.remove('active');
    
    // Hide workout cards
    const todayWorkoutCard = document.querySelector('.today-workout-card');
    const workoutsCard = document.querySelector('.workouts-card');
    const strengthWorkoutsCard = document.querySelector('.strength-workouts-card');
    
    if (todayWorkoutCard) {
        todayWorkoutCard.style.setProperty('display', 'none', 'important');
    }
    if (workoutsCard) {
        workoutsCard.style.setProperty('display', 'none', 'important');
    }
    if (strengthWorkoutsCard) {
        strengthWorkoutsCard.style.setProperty('display', 'none', 'important');
    }
    
    // Hide headings
    const todayHeading = document.getElementById('todayHeading');
    const selectedHeading = document.getElementById('selectedHeading');
    
    if (todayHeading) todayHeading.style.display = 'none';
    if (selectedHeading) selectedHeading.style.display = 'none';
    
    // Hide phase tabs
    const phaseTabsContainer = document.querySelector('.strength-phase-tabs');
    if (phaseTabsContainer) {
        phaseTabsContainer.style.setProperty('display', 'none', 'important');
    }
    
    // Hide tabs container
    const cardHeaderTabs = document.querySelector('.card-header-tabs');
    if (cardHeaderTabs) {
        if (!cardHeaderTabs.closest('.gym-membership-tabs-container')) {
        cardHeaderTabs.style.setProperty('display', 'none', 'important');
        }
    }
    
    // Hide the entire today-workout-card (which contains tabs and content)
    if (todayWorkoutCard) {
        todayWorkoutCard.style.setProperty('display', 'none', 'important');
    }
    
    // Ensure dashboard card is visible
    const dashboardCard = document.querySelector('.dashboard-card');
    if (dashboardCard) {
        dashboardCard.style.display = 'block';
    }
    
    // Show subscription card
    const subscriptionCard = document.querySelector('.subscription-card');
    if (subscriptionCard) {
        subscriptionCard.style.display = 'block';
        // Ensure subscription status is rendered
        renderSubscriptionStatus();
    }
    
    // Show gym membership card
    const gymMembershipCard = document.querySelector('.gym-membership-card');
    if (gymMembershipCard) {
        gymMembershipCard.style.display = 'block';
        // Enable the card (remove any graying out)
        gymMembershipCard.style.opacity = '1';
        gymMembershipCard.style.pointerEvents = 'auto';
        gymMembershipCard.style.filter = 'none';
        
        // Re-hide workout cards after renderSubscriptionStatus (in case it tried to show them)
        // Use multiple timeouts to ensure they stay hidden
        const hideWorkoutCards = () => {
            const todayWorkoutCardAfter = document.querySelector('.today-workout-card');
            const workoutsCardAfter = document.querySelector('.workouts-card');
            const strengthWorkoutsCardAfter = document.querySelector('.strength-workouts-card');
            const cardHeaderTabsAfter = document.querySelector('.card-header-tabs');
            
            if (todayWorkoutCardAfter) {
                todayWorkoutCardAfter.style.setProperty('display', 'none', 'important');
            }
            if (workoutsCardAfter) {
                workoutsCardAfter.style.setProperty('display', 'none', 'important');
            }
            if (strengthWorkoutsCardAfter) {
                strengthWorkoutsCardAfter.style.setProperty('display', 'none', 'important');
            }
            // Hide tabs container again (but not gym membership tabs)
            if (cardHeaderTabsAfter && !cardHeaderTabsAfter.closest('.gym-membership-tabs-container')) {
                cardHeaderTabsAfter.style.setProperty('display', 'none', 'important');
            }
        };
        
        // Hide immediately and then again after a short delay
        hideWorkoutCards();
        setTimeout(hideWorkoutCards, 50);
        setTimeout(hideWorkoutCards, 100);
        setTimeout(hideWorkoutCards, 200);
        
        // Load and display gym membership details
        loadGymMembershipDetails();
    }
}

