function openMembershipWizardWithType(type) {
    const membershipType = String(type || '').trim().toUpperCase();
    if (!membershipType) return;
    try {
        sessionStorage.setItem('prefillMembershipType', membershipType);
    } catch (e) {
        // ignore
    }
    const wizardContainer = document.getElementById('membershipSignupWizard');
    if (!wizardContainer) {
        alert('Signup form not found. Please refresh the page.');
        return;
    }
    if (typeof window.openMembershipSignupWizard === 'function') {
        window.openMembershipSignupWizard();
    } else if (typeof window.initMembershipSignupWizard === 'function') {
        wizardContainer.style.display = 'block';
        window.initMembershipSignupWizard();
    } else {
        wizardContainer.style.display = 'block';
        alert('The signup form is loading. Please try again in a moment.');
    }
}

