            // Render the default workout
            if (strengthWorkoutContent && defaultWorkout) {
                renderStrengthWorkout(defaultWorkout);
            } else if (strengthWorkoutContent) {
                strengthWorkoutContent.innerHTML = '<p class="loading">No strength workouts available yet.</p>';
            }
            
            // Build complete carousel list including default workout
            const allCarouselWorkouts = [];
            filteredWorkouts.forEach(w => {
                if (!defaultWorkout || w.id !== defaultWorkout.id) {
                    allCarouselWorkouts.push(w);
                }
            });
            if (defaultWorkout) {
                allCarouselWorkouts.push(defaultWorkout);
            }
            
            // Sort carousel workouts by ID ascending
