// Setup collapsible sections for body comp log and 1RM log
function setupCollapsibleSections() {
    const sectionHeaders = document.querySelectorAll('.section-header');
    sectionHeaders.forEach(header => {
        // Skip if already set up
        if (header.dataset.listenersAdded === 'true') {
            return;
        }
        
        const toggleBtn = header.querySelector('.section-toggle-btn');
        const section = header.getAttribute('data-section');
        
        if (toggleBtn) {
            // Find the table that contains this header
            const table = header.closest('table');
            if (!table) return;
            
            // Find all rows that belong to this section (until next section header)
            const allRows = Array.from(table.querySelectorAll('tbody tr'));
            const headerIndex = allRows.indexOf(header);
            const sectionRows = [];
            
            for (let i = headerIndex + 1; i < allRows.length; i++) {
                const row = allRows[i];
                if (row.classList.contains('section-header')) {
                    break; // Stop at next section header
                }
                if (row.classList.contains('section-row') && row.classList.contains(`section-${section}`)) {
                    sectionRows.push(row);
                }
            }
            
            toggleBtn.addEventListener('click', () => {
                const isExpanded = header.classList.contains('expanded');
                const icon = toggleBtn.querySelector('.section-toggle-icon');
                
                if (isExpanded) {
                    // Collapse
                    header.classList.remove('expanded');
                    sectionRows.forEach(row => {
                        row.style.display = 'none';
                    });
                    if (icon) icon.textContent = '▶';
                } else {
                    // Expand
                    header.classList.add('expanded');
                    sectionRows.forEach(row => {
                        row.style.display = 'table-row';
                    });
                    if (icon) icon.textContent = '▼';
                }
            });
            
            // Expand by default
            header.classList.add('expanded');
            
            // Mark as set up
            header.dataset.listenersAdded = 'true';
        }
    });
}

