// Delete a PR log entry
async function deletePRLog(logId) {
    if (!confirm('Are you sure you want to delete this PR log entry?')) {
        return;
    }
    
    try {
        const response = await fetch(`${API_BASE}/pr-logs/${logId}`, {
            method: 'DELETE',
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });
        
        if (response.ok) {
            // Reload the PR logs display
            await loadPRLogs();
        } else {
            const error = await response.json();
            alert('Error deleting PR log: ' + (error.error || 'Please try again.'));
        }
    } catch (error) {
        console.error('Error deleting PR log:', error);
        alert('Error deleting PR log. Please try again.');
    }
}

// Make deletePRLog globally available
window.deletePRLog = deletePRLog;

// Categorize exercise for grouping
function categorizeExercise(exercise) {
    const lowerCase = exercise.toLowerCase();
    
    // Lower body exercises
    const lowerBodyKeywords = ['squat', 'deadlift', 'leg press', 'lunges', 'lunge', 'leg curl', 'leg extension', 
                                'calf', 'hip thrust', 'good morning', 'romanian', 'rdl', 'bulgarian', 'split squat',
                                'hack squat', 'front squat', 'back squat', 'sumo', 'conventional', 'trap bar'];
    if (lowerBodyKeywords.some(keyword => lowerCase.includes(keyword))) {
        return 'lower';
    }
    
    // Upper body exercises
    const upperBodyKeywords = ['bench', 'press', 'pull', 'row', 'curl', 'tricep', 'shoulder', 'lat', 'chest', 
                               'bicep', 'dumbbell', 'barbell', 'push up', 'pull up', 'chin up', 'dip', 'fly',
                               'lateral raise', 'overhead', 'ohp', 'military', 'incline', 'decline', 'pec',
                               'rear delt', 'front raise', 'arnold'];
    if (upperBodyKeywords.some(keyword => lowerCase.includes(keyword))) {
        return 'upper';
    }
    
    // Default to other
    return 'other';
}

// Migrate PR logs from localStorage to database
async function migratePRLogsFromLocalStorage() {
    if (!currentUser || !currentUser.id) return;
    
    const userId = currentUser.id;
    const storageKey = `pr_logs_${userId}`;
    const migrationKey = `pr_logs_migrated_${userId}`;
    
    // Check if already migrated
    if (localStorage.getItem(migrationKey)) {
        return;
    }
    
    try {
        // Get logs from localStorage
        const stored = localStorage.getItem(storageKey);
        if (!stored) return;
        
        const localLogs = JSON.parse(stored);
        if (!Array.isArray(localLogs) || localLogs.length === 0) return;
        
        // Check if database already has logs
        const response = await fetch(`${API_BASE}/pr-logs`, {
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });
        
        if (response.ok) {
            const data = await response.json();
            if (data.logs && data.logs.length > 0) {
                // Database already has logs, mark as migrated
                localStorage.setItem(migrationKey, 'true');
                return;
            }
        }
        
        // Migrate logs to database
        const logsToMigrate = localLogs.map(log => ({
            exercise: log.exercise,
            weight: parseFloat(log.weight),
            reps: parseInt(log.reps),
            oneRM: parseFloat(log.oneRM),
            confidence: log.confidence,
            date: log.date
        }));
        
        const migrateResponse = await fetch(`${API_BASE}/pr-logs/bulk`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify({ logs: logsToMigrate })
        });
        
        if (migrateResponse.ok) {
            // Mark as migrated
            localStorage.setItem(migrationKey, 'true');
            console.log(`Migrated ${logsToMigrate.length} PR logs to database`);
        }
    } catch (error) {
        console.error('Error migrating PR logs:', error);
    }
}

// Migrate body composition measurements from localStorage to database
async function migrateBodyCompositionFromLocalStorage() {
    if (!currentUser || !currentUser.id) return;
    
    const userId = currentUser.id;
    const storageKey = 'bodyCompositionMeasurements';
    const migrationKey = `body_comp_migrated_${userId}`;
    
    // Check if already migrated
    if (localStorage.getItem(migrationKey)) {
        return;
    }
    
    try {
        // Get measurements from localStorage
        const stored = localStorage.getItem(storageKey);
        if (!stored) return;
        
        const localMeasurements = JSON.parse(stored);
        if (!Array.isArray(localMeasurements) || localMeasurements.length === 0) return;
        
        // Check if database already has measurements
        const response = await fetch(`${API_BASE}/body-composition`, {
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });
        
        if (response.ok) {
            const data = await response.json();
            if (data.measurements && data.measurements.length > 0) {
                // Database already has measurements, mark as migrated
                localStorage.setItem(migrationKey, 'true');
                return;
            }
        }
        
        // Migrate measurements to database (only for current user's data if we can identify it)
        // Note: Since localStorage was global, we'll migrate all if user is logged in
        const measurementsToMigrate = localMeasurements
            .filter(m => m && m.measurement && m.value !== undefined)
            .map(m => ({
                measurement: m.measurement,
                value: parseFloat(m.value),
                goalDirection: m.goalDirection || 'increase',
                date: m.date || m.measurement_date || new Date().toISOString()
            }));
        
        if (measurementsToMigrate.length > 0) {
            const migrateResponse = await fetch(`${API_BASE}/body-composition/bulk`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ measurements: measurementsToMigrate })
            });
            
            if (migrateResponse.ok) {
                // Mark as migrated
                localStorage.setItem(migrationKey, 'true');
                console.log(`Migrated ${measurementsToMigrate.length} body composition measurements to database`);
            }
        }
    } catch (error) {
        console.error('Error migrating body composition measurements:', error);
    }
}

// Get trend indicator for a PR log (always green for up, red for down)
function getPRTrendIndicator(log, allLogs) {
    // Find all entries with the same exercise name, sorted by date (newest first)
    const sameExercises = allLogs
        .filter(l => l.exercise.toLowerCase().trim() === log.exercise.toLowerCase().trim())
        .sort((a, b) => new Date(b.date) - new Date(a.date));
    
    // Find the index of the current log in the sorted list
    // Match by ID only since each log has a unique ID
    const currentIndex = sameExercises.findIndex(l => 
        String(l.id) === String(log.id)
    );
    
    // If this is the last entry (oldest) for this exercise, show gray circle
    if (currentIndex === -1 || currentIndex === sameExercises.length - 1) {
        return '<span class="trend-indicator trend-neutral">●</span>';
    }
    
    // Get the previous log (the one entered before this one)
    const previousLog = sameExercises[currentIndex + 1];
    const currentValue = parseFloat(log.oneRM);
    const previousValue = parseFloat(previousLog.oneRM);
    
    // Determine if 1RM went up or down
    const wentUp = currentValue > previousValue;
    const wentDown = currentValue < previousValue;
    
    // If no change, show gray circle
    if (!wentUp && !wentDown) {
        return '<span class="trend-indicator trend-neutral">●</span>';
    }
    
    // Up is always green, down is always red
    const colorClass = wentUp ? 'trend-good' : 'trend-bad';
    const arrow = wentUp ? '↑' : '↓';
    
    return `<span class="trend-indicator ${colorClass}">${arrow}</span>`;
}

// Load and display PR logs
async function loadPRLogs() {
    const logsList = document.getElementById('prLogsList');
    if (!logsList) return;
    
    // Show loading state
    logsList.innerHTML = '<p style="text-align: center; color: #666; padding: 2rem;">Loading...</p>';
    
    // Migrate from localStorage if needed
    await migratePRLogsFromLocalStorage();
    
    // Fetch PR logs from API
    let prLogs = [];
    try {
        const response = await fetch(`${API_BASE}/pr-logs`, {
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });
        
        if (response.ok) {
            const data = await response.json();
            prLogs = data.logs || [];
        } else {
            console.error('Failed to load PR logs:', response.status);
        }
    } catch (error) {
        console.error('Error loading PR logs:', error);
        logsList.innerHTML = '<p style="text-align: center; color: #dc3545; padding: 2rem;">Error loading PR logs. Please try again.</p>';
        return;
    }
    
    if (prLogs.length === 0) {
        logsList.innerHTML = '<p style="text-align: center; color: #666; padding: 2rem;">No PRs logged yet. Calculate a 1RM and log it to see it here!</p>';
        return;
    }
    
    // Sort logs by date (newest first)
    prLogs.sort((a, b) => new Date(b.date) - new Date(a.date));
    
    // Group logs by category
    const grouped = {
        upper: [],
        lower: [],
        other: []
    };
    
    prLogs.forEach(log => {
        const category = categorizeExercise(log.exercise);
        grouped[category].push(log);
    });
    
    // Build table HTML using body composition table style
    let tableHTML = '<div class="body-comp-log-table-container"><table class="body-comp-log-table"><thead><tr><th>Trend</th><th>Date</th><th>Exercise</th><th>Weight</th><th>Reps</th><th>1RM</th><th>Confidence</th><th>Action</th></tr></thead><tbody>';
    
    // Add Upper Body section header if there are upper body exercises
    if (grouped.upper.length > 0) {
        tableHTML += `<tr class="section-header" data-section="upper">
            <td colspan="8">
                <button type="button" class="section-toggle-btn" aria-label="Toggle Upper Body section">
                    <span class="section-title">Upper Body</span>
                    <span class="section-toggle-icon">▼</span>
                </button>
            </td>
        </tr>`;
        
        grouped.upper.forEach(log => {
            const date = new Date(log.date);
            const dateStr = date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
            const trendIndicator = getPRTrendIndicator(log, prLogs);
            const confidenceColors = {
                'high': '#28a745',
                'medium': '#ffc107',
                'low': '#dc3545'
            };
            const confidenceText = {
                'high': 'High',
                'medium': 'Medium',
                'low': 'Low'
            };
            tableHTML += `<tr class="section-row section-upper">
                <td>${trendIndicator}</td>
                <td>${dateStr}</td>
                <td>${log.exercise}</td>
                <td>${log.weight}</td>
                <td>${log.reps}</td>
                <td>${log.oneRM}</td>
                <td><span style="color: ${confidenceColors[log.confidence]}; font-weight: 600; text-transform: uppercase; font-size: 0.75rem;">${confidenceText[log.confidence]}</span></td>
                <td><button type="button" class="delete-measurement-btn" onclick="deletePRLog('${log.id}')" aria-label="Delete PR log">Delete</button></td>
            </tr>`;
        });
    }
    
    // Add Lower Body section header if there are lower body exercises
    if (grouped.lower.length > 0) {
        tableHTML += `<tr class="section-header" data-section="lower">
            <td colspan="8">
                <button type="button" class="section-toggle-btn" aria-label="Toggle Lower Body section">
                    <span class="section-title">Lower Body</span>
                    <span class="section-toggle-icon">▼</span>
                </button>
            </td>
        </tr>`;
        
        grouped.lower.forEach(log => {
            const date = new Date(log.date);
            const dateStr = date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
            const trendIndicator = getPRTrendIndicator(log, prLogs);
            const confidenceColors = {
                'high': '#28a745',
                'medium': '#ffc107',
                'low': '#dc3545'
            };
            const confidenceText = {
                'high': 'High',
                'medium': 'Medium',
                'low': 'Low'
            };
            tableHTML += `<tr class="section-row section-lower">
                <td>${trendIndicator}</td>
                <td>${dateStr}</td>
                <td>${log.exercise}</td>
                <td>${log.weight}</td>
                <td>${log.reps}</td>
                <td>${log.oneRM}</td>
                <td><span style="color: ${confidenceColors[log.confidence]}; font-weight: 600; text-transform: uppercase; font-size: 0.75rem;">${confidenceText[log.confidence]}</span></td>
                <td><button type="button" class="delete-measurement-btn" onclick="deletePRLog('${log.id}')" aria-label="Delete PR log">Delete</button></td>
            </tr>`;
        });
    }
    
    // Add Other section header if there are other exercises
    if (grouped.other.length > 0) {
        tableHTML += `<tr class="section-header" data-section="other">
            <td colspan="8">
                <button type="button" class="section-toggle-btn" aria-label="Toggle Other section">
                    <span class="section-title">Other</span>
                    <span class="section-toggle-icon">▼</span>
                </button>
            </td>
        </tr>`;
        
        grouped.other.forEach(log => {
            const date = new Date(log.date);
            const dateStr = date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
            const trendIndicator = getPRTrendIndicator(log, prLogs);
            const confidenceColors = {
                'high': '#28a745',
                'medium': '#ffc107',
                'low': '#dc3545'
            };
            const confidenceText = {
                'high': 'High',
                'medium': 'Medium',
                'low': 'Low'
            };
            tableHTML += `<tr class="section-row section-other">
                <td>${trendIndicator}</td>
                <td>${dateStr}</td>
                <td>${log.exercise}</td>
                <td>${log.weight}</td>
                <td>${log.reps}</td>
                <td>${log.oneRM}</td>
                <td><span style="color: ${confidenceColors[log.confidence]}; font-weight: 600; text-transform: uppercase; font-size: 0.75rem;">${confidenceText[log.confidence]}</span></td>
                <td><button type="button" class="delete-measurement-btn" onclick="deletePRLog('${log.id}')" aria-label="Delete PR log">Delete</button></td>
            </tr>`;
        });
    }
    
    tableHTML += '</tbody></table></div>';
    logsList.innerHTML = tableHTML;
    
    // Setup collapsible sections
    setupCollapsibleSections();
}

