// Make togglePRInstruction globally available
window.togglePRInstruction = togglePRInstruction;

// Setup collapsible sections for progressive overload
function setupProgressiveOverloadCollapsible() {
    // Setup main exercise headers (blue headers)
    const mainToggleButtons = document.querySelectorAll('.progressive-overload-toggle-btn-main');
    mainToggleButtons.forEach(button => {
        // Skip if already set up
        if (button.dataset.listenersAdded === 'true') {
            return;
        }
        
        button.addEventListener('click', () => {
            const exerciseId = button.getAttribute('data-exercise-id');
            const content = document.querySelector(`.progressive-overload-main-content[data-exercise-id="${exerciseId}"]`);
            const icon = button.querySelector('.progressive-overload-toggle-icon-main');
            
            if (content) {
                const isExpanded = content.style.display !== 'none';
                
                if (isExpanded) {
                    // Collapse
                    content.style.display = 'none';
                    if (icon) {
                        icon.style.transform = 'rotate(-90deg)';
                    }
                } else {
                    // Expand
                    content.style.display = 'block';
                    if (icon) {
                        icon.style.transform = 'rotate(0deg)';
                    }
                }
            }
        });
        
        // Mark as set up
        button.dataset.listenersAdded = 'true';
    });
    
    // Setup older entries toggle buttons
    const toggleButtons = document.querySelectorAll('.progressive-overload-toggle-btn');
    toggleButtons.forEach(button => {
        // Skip if already set up
        if (button.dataset.listenersAdded === 'true') {
            return;
        }
        
        button.addEventListener('click', () => {
            const exerciseId = button.getAttribute('data-exercise-id');
            const content = document.querySelector(`.progressive-overload-collapsible-content[data-exercise-id="${exerciseId}"]`);
            const icon = button.querySelector('.progressive-overload-toggle-icon');
            
            if (content) {
                const isExpanded = content.style.display !== 'none';
                
                if (isExpanded) {
                    // Collapse
                    content.style.display = 'none';
                    if (icon) {
                        icon.style.transform = 'rotate(0deg)';
                    }
                    button.style.background = '#f8f9fa';
                } else {
                    // Expand
                    content.style.display = 'block';
                    if (icon) {
                        icon.style.transform = 'rotate(180deg)';
                    }
                    button.style.background = '#e9ecef';
                }
            }
        });
        
        // Mark as set up
        button.dataset.listenersAdded = 'true';
    });
}

// Store current calculation data for logging
let currentPRData = null;

// Calculate 1RM using the specified algorithm
function calculate1RM() {
    // Get inputs
    const weight = parseFloat(document.getElementById('prWeight').value);
    const reps = parseInt(document.getElementById('prReps').value);
    const exerciseSelect = document.getElementById('prExercise');
    const exerciseCustomInput = document.getElementById('prExerciseCustom');
    let exerciseType = exerciseSelect.value;
    
    // If "Other" is selected, use the custom input value
    if (exerciseType === 'other') {
        if (!exerciseCustomInput || !exerciseCustomInput.value.trim()) {
            alert('Please enter a custom exercise name');
            return;
        }
        exerciseType = exerciseCustomInput.value.trim();
    }
    
    // Validate inputs
    if (!weight || weight <= 0 || !reps || reps < 1) {
        alert('Please enter valid weight and reps');
        return;
    }
    
    if (!exerciseType) {
        alert('Please select or enter an exercise type');
        return;
    }
    
    // Step 1: Compute four base 1RM estimates
    const estimates = [];
    
    // Epley: 1RM = weight × (1 + reps / 30)
    estimates.push(weight * (1 + reps / 30));
    
    // Brzycki: 1RM = weight × 36 / (37 − reps) - skip if reps >= 37
    if (reps < 37) {
        estimates.push(weight * 36 / (37 - reps));
    }
    
    // Lombardi: 1RM = weight × reps^0.10
    estimates.push(weight * Math.pow(reps, 0.10));
    
    // O'Conner: 1RM = weight × (1 + 0.025 × reps)
    estimates.push(weight * (1 + 0.025 * reps));
    
    // Step 2: Take median of estimates
    estimates.sort((a, b) => a - b);
    const medianIndex = Math.floor(estimates.length / 2);
    let base1RM = estimates.length % 2 === 0
        ? (estimates[medianIndex - 1] + estimates[medianIndex]) / 2
        : estimates[medianIndex];
    
    // Step 3: Adjust based on exercise type
    let exerciseMultiplier = 1.0;
    let maxUsefulReps = 10;
    
    // Map dropdown values to exercise categories for calculation
    // Heavy lower-body compounds
    if (exerciseType === 'barbell-back-squat' || exerciseType === 'back-squat') {
        exerciseMultiplier = 0.97;
        maxUsefulReps = 8;
    } else if (exerciseType === 'barbell-front-squat' || exerciseType === 'front-squat') {
        exerciseMultiplier = 0.96;
        maxUsefulReps = 8;
    } else if (exerciseType === 'barbell-deadlift' || exerciseType === 'deadlift') {
        exerciseMultiplier = 0.95;
        maxUsefulReps = 5;
    } else if (exerciseType === 'barbell-rdl') {
        exerciseMultiplier = 0.95;
        maxUsefulReps = 8;
    } else if (exerciseType === 'barbell-hip-thrust') {
        exerciseMultiplier = 0.97;
        maxUsefulReps = 8;
    } else if (exerciseType === 'barbell-power-clean') {
        exerciseMultiplier = 0.98;
        maxUsefulReps = 5;
    }
    // Upper-body compounds
    else if (exerciseType === 'barbell-bench-press' || exerciseType === 'bench-press') {
        exerciseMultiplier = 1.00;
        maxUsefulReps = 10;
    } else if (exerciseType === 'barbell-overhead-press-strict' || exerciseType === 'barbell-overhead-press-push' || exerciseType === 'overhead-press') {
        exerciseMultiplier = 0.98;
        maxUsefulReps = 10;
    } else if (exerciseType === 'barbell-bent-over-row' || exerciseType === 'row') {
        exerciseMultiplier = 1.00;
        maxUsefulReps = 10;
    } else if (exerciseType === 'pullup') {
        exerciseMultiplier = 1.02;
        maxUsefulReps = 10;
    }
    // Isolation movements
    else if (exerciseType === 'barbell-curl' || exerciseType === 'dumbbell-tricep-kickback' || exerciseType === 'isolation-upper' || exerciseType === 'isolation-lower') {
        exerciseMultiplier = 0.95;
        maxUsefulReps = 10;
    }
    // Machines
    else if (exerciseType === 'machine') {
        exerciseMultiplier = 1.00;
        maxUsefulReps = 10;
    }
    // Custom exercises (default multiplier)
    else {
        exerciseMultiplier = 1.0;
        maxUsefulReps = 10;
    }
    
    base1RM = base1RM * exerciseMultiplier;
    
    // Step 4: Final 1RM (no calibration)
    const final1RM = base1RM;
    
    // Step 5: Determine confidence and error range
    const isBigCompound = ['barbell-back-squat', 'barbell-front-squat', 'barbell-deadlift', 'barbell-rdl', 'barbell-hip-thrust', 'barbell-power-clean', 'barbell-bench-press', 'barbell-overhead-press-strict', 'barbell-overhead-press-push', 'barbell-bent-over-row', 'back-squat', 'front-squat', 'deadlift', 'bench-press', 'overhead-press', 'row', 'pullup'].includes(exerciseType);
    const isIsolationOrMachine = ['barbell-curl', 'dumbbell-tricep-kickback', 'isolation-upper', 'isolation-lower', 'machine'].includes(exerciseType);
    
    let confidence = 'low';
    let error = 0.15;
    
    if (isBigCompound) {
        if (reps >= 1 && reps <= 5 && reps <= maxUsefulReps) {
            confidence = 'high';
            error = 0.05;
        } else if (reps >= 6 && reps <= 10 && reps <= maxUsefulReps) {
            confidence = 'medium';
            error = 0.10;
        } else {
            confidence = 'low';
            error = 0.15;
        }
    } else if (isIsolationOrMachine) {
        if (reps > 10) {
            confidence = 'low';
            error = 0.15;
        } else {
            confidence = 'medium';
            error = 0.10;
        }
    } else {
        // Default case
        if (reps > maxUsefulReps) {
            confidence = 'low';
            error = 0.15;
        } else if (reps > 5) {
            confidence = 'medium';
            error = 0.10;
        } else {
            confidence = 'high';
            error = 0.05;
        }
    }
    
    // Calculate bounds
    const lowerBound = final1RM * (1 - error);
    const upperBound = final1RM * (1 + error);
    
    // Map exercise value to display name for dropdown options
    const exerciseDisplayMap = {
        'barbell-back-squat': 'Barbell Back Squat',
        'barbell-front-squat': 'Barbell Front Squat',
        'barbell-deadlift': 'Barbell Deadlift',
        'barbell-rdl': 'Barbell Romanian Deadlift (RDL)',
        'barbell-bench-press': 'Barbell Bench Press',
        'barbell-overhead-press-strict': 'Barbell Overhead Press (Strict Press)',
        'barbell-bent-over-row': 'Barbell Bent-Over Row',
        'barbell-hip-thrust': 'Barbell Hip Thrust',
        'barbell-power-clean': 'Barbell Power Clean',
        'barbell-overhead-press-push': 'Barbell Overhead Press (Push Press)',
        'barbell-curl': 'Barbell Curl',
        'dumbbell-tricep-kickback': 'Dumbbell Tricep Kickback'
    };
    
    // Get display name (use mapped name if available, otherwise use the exerciseType as-is for custom exercises)
    const exerciseDisplayName = exerciseDisplayMap[exerciseType] || exerciseType;
    
    // Store calculation data for logging
    currentPRData = {
        weight: weight,
        reps: reps,
        exercise: exerciseDisplayName,
        oneRM: final1RM,
        confidence: confidence,
        date: new Date().toISOString()
    };
    
    // Display results first
    displayPRResults(final1RM, lowerBound, upperBound, confidence);
}

// Display PR Calculator results
function displayPRResults(oneRM, lowerBound, upperBound, confidence) {
    const resultsDiv = document.getElementById('prResults');
    const oneRMDiv = document.getElementById('prOneRM');
    const confidenceDiv = document.getElementById('prConfidence');
    const logPRBtn = document.getElementById('logPRBtn');
    
    if (resultsDiv && oneRMDiv && confidenceDiv) {
        oneRMDiv.textContent = `${Math.round(oneRM)} lbs`;
        
        const confidenceColors = {
            'high': '#28a745',
            'medium': '#ffc107',
            'low': '#dc3545'
        };
        const confidenceText = {
            'high': 'High',
            'medium': 'Medium',
            'low': 'Low'
        };
        
        confidenceDiv.innerHTML = `<span style="color: ${confidenceColors[confidence]}; font-weight: 600; text-transform: uppercase;">${confidenceText[confidence]}</span>`;
        
        // Show log button if we have PR data
        if (logPRBtn && currentPRData) {
            logPRBtn.style.display = 'block';
        }
        
        resultsDiv.style.display = 'block';
        
        // Scroll results into view
        setTimeout(() => {
            resultsDiv.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        }, 100);
    }
}

// Handle logging PR data
async function handleLogPR() {
    if (!currentPRData) {
        alert('No PR data to log. Please calculate a 1RM first.');
        return;
    }
    
    // Save PR log to API
    try {
        const response = await fetch(`${API_BASE}/pr-logs`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify({
                exercise: currentPRData.exercise,
                weight: currentPRData.weight,
                reps: currentPRData.reps,
                oneRM: Math.round(currentPRData.oneRM),
                confidence: currentPRData.confidence,
                date: currentPRData.date
            })
        });
        
        if (response.ok) {
            // Switch to PR Log tab instead of showing alert
            switchPersonalStrengthCoachTab('pr-log');
            // Reload PR logs to show the new entry
            await loadPRLogs();
        } else {
            const error = await response.json();
            // Check if it's a tier limit error
            if (response.status === 403 && error.error && error.error.includes('limit')) {
                // Show upgrade modal instead of alert
                showUpgradeModal(
                    error.error,
                    '1RM Lifts'
                );
            } else {
                alert('Error saving PR log: ' + (error.error || 'Please try again.'));
            }
        }
    } catch (error) {
        console.error('Error saving PR log:', error);
        alert('Error saving PR log. Please try again.');
    }
}

// Filter strength workouts by phase
function filterStrengthWorkoutsByPhase(workouts, phase) {
    // Map phase tab labels to phase values
    let phaseValue = null;
    if (phase === 'Phase One: Beginner') {
        phaseValue = 'Phase One';
    } else if (phase === 'Phase Two: Intermediate') {
        phaseValue = 'Phase Two';
    } else if (phase === 'Phase Three: Advanced') {
        phaseValue = 'Phase Three';
    }
    
    if (!phaseValue) {
        return workouts; // Return all if phase doesn't match
    }
    
    // Filter workouts - handle both "Phase One" and "Phase One: Beginner" formats
    return workouts.filter(workout => {
        const workoutPhase = workout.phase || '';
        // Exact match
        if (workoutPhase === phaseValue) return true;
        // Match if workout phase starts with the phase value (handles "Phase One: Beginner")
        if (workoutPhase.startsWith(phaseValue + ':') || workoutPhase.startsWith(phaseValue + ' ')) {
            return true;
        }
        // Case-insensitive match
        const workoutPhaseLower = workoutPhase.toLowerCase();
        const phaseValueLower = phaseValue.toLowerCase();
        if (workoutPhaseLower === phaseValueLower || workoutPhaseLower.startsWith(phaseValueLower + ':') || workoutPhaseLower.startsWith(phaseValueLower + ' ')) {
            return true;
        }
        return false;
    });
}

// Filter and display strength workouts based on selected phase
async function filterAndDisplayStrengthWorkouts(phase) {
    const strengthWorkoutsCarousel = document.getElementById('strengthWorkoutsCarousel');
    const strengthWorkoutsCarouselContainer = document.getElementById('strengthWorkoutsCarouselContainer');
    const strengthWorkoutsCard = document.querySelector('.strength-workouts-card');
    const strengthWorkoutsEmpty = document.getElementById('strengthWorkoutsEmpty');
    const strengthWorkoutContent = document.getElementById('strengthContent')?.querySelector('.today-workout-content');
    const selectedHeading = document.getElementById('selectedHeading');
    const strengthSelectedHeading = document.getElementById('strengthSelectedHeading');
    
    // Show main "Strength Workouts" header, hide subheader
    if (selectedHeading) {
        selectedHeading.textContent = 'Strength Workouts';
        selectedHeading.style.display = 'block';
    }
    if (strengthSelectedHeading) {
        strengthSelectedHeading.style.display = 'none';
    }
    
    // Show the carousel (in case it was hidden by PR Calc)
    if (strengthWorkoutsCarouselContainer) {
        strengthWorkoutsCarouselContainer.style.display = 'block';
    }
    if (strengthWorkoutsCard) {
        strengthWorkoutsCard.style.display = 'block';
    }
    
    // Filter workouts by phase
    const filteredWorkouts = filterStrengthWorkoutsByPhase(allStrengthWorkouts, phase);
    
    if (filteredWorkouts.length === 0) {
        if (strengthWorkoutContent) {
            strengthWorkoutContent.innerHTML = '<p class="loading">No workouts available for this phase.</p>';
        }
        if (strengthWorkoutsCarousel) {
            strengthWorkoutsCarousel.innerHTML = '';
        }
        if (strengthWorkoutsEmpty) {
            strengthWorkoutsEmpty.textContent = 'No workouts available for this phase.';
            strengthWorkoutsEmpty.style.display = 'block';
        }
        return;
    }
    
    // Get default workout (first workout in phase, sorted by ID ascending)
    let defaultWorkout = null;
    const sortedWorkouts = [...filteredWorkouts].sort((a, b) => a.id - b.id);
    defaultWorkout = sortedWorkouts[0];
    
    // Fetch full content for default workout with blocks and exercises
    try {
        const workoutResponse = await fetch(`${API_BASE}/strength-workouts/${defaultWorkout.id}`, {
            headers: {
                'Authorization': `Bearer ${token}`
            }
        });
        if (workoutResponse.ok) {
            const workoutData = await workoutResponse.json();
            defaultWorkout = workoutData.workout;
        }
    } catch (error) {
        console.error('Error fetching workout content:', error);
    }
    
    // Render default workout
    if (strengthWorkoutContent && defaultWorkout) {
        renderStrengthWorkout(defaultWorkout);
    }
    
    // Build carousel
    const allCarouselWorkouts = [];
    filteredWorkouts.forEach(w => {
        if (!defaultWorkout || w.id !== defaultWorkout.id) {
            allCarouselWorkouts.push(w);
        }
    });
    if (defaultWorkout) {
        allCarouselWorkouts.push(defaultWorkout);
    }
    
    // Sort by ID ascending
    allCarouselWorkouts.sort((a, b) => a.id - b.id);
    
    // Render carousel
    if (strengthWorkoutsCarousel && strengthWorkoutsCarouselContainer) {
        strengthWorkoutsCarousel.innerHTML = allCarouselWorkouts.map((workout) => {
            const isSelected = defaultWorkout && workout.id === defaultWorkout.id;
            return renderStrengthCarouselCard(workout, isSelected, false);
        }).join('');
        
        // Scroll to selected card
        setTimeout(() => {
            const selectedCard = strengthWorkoutsCarousel.querySelector('.carousel-card.selected');
            if (selectedCard) {
                const offsetLeft = selectedCard.offsetLeft;
                const cardWidth = selectedCard.offsetWidth;
                const containerWidth = strengthWorkoutsCarousel.clientWidth;
                const scrollLeft = offsetLeft - (containerWidth / 2) + (cardWidth / 2);
                strengthWorkoutsCarousel.scrollLeft = scrollLeft;
            }
        }, 0);
        
        strengthWorkoutsCarouselContainer.style.display = 'block';
        if (strengthWorkoutsEmpty) {
            strengthWorkoutsEmpty.style.display = 'none';
        }
    }
}

