// Normalize distribution columns to ensure they sum to exactly 100%
function normalizeDistributionColumns(container) {
    const proteinInputs = Array.from(container.querySelectorAll('.pt-protein-input'));
    const fatInputs = Array.from(container.querySelectorAll('.pt-fat-input'));
    const carbsInputs = Array.from(container.querySelectorAll('.pt-carbs-input'));
    
    // Normalize protein column
    let proteinTotal = proteinInputs.reduce((sum, input) => sum + (parseFloat(input.value) || 0), 0);
    if (Math.abs(proteinTotal - 100) > 0.01) {
        const factor = 100 / proteinTotal;
        proteinInputs.forEach(input => {
            const newValue = (parseFloat(input.value) || 0) * factor;
            input.value = Math.round(newValue * 10) / 10;
        });
    }
    
    // Normalize fat column
    let fatTotal = fatInputs.reduce((sum, input) => sum + (parseFloat(input.value) || 0), 0);
    if (Math.abs(fatTotal - 100) > 0.01) {
        const factor = 100 / fatTotal;
        fatInputs.forEach(input => {
            const newValue = (parseFloat(input.value) || 0) * factor;
            input.value = Math.round(newValue * 10) / 10;
        });
    }
    
    // Normalize carbs column
    let carbsTotal = carbsInputs.reduce((sum, input) => sum + (parseFloat(input.value) || 0), 0);
    if (Math.abs(carbsTotal - 100) > 0.01) {
        const factor = 100 / carbsTotal;
        carbsInputs.forEach(input => {
            const newValue = (parseFloat(input.value) || 0) * factor;
            input.value = Math.round(newValue * 10) / 10;
        });
    }
}

// Setup handlers for macro distribution table
function setupMacroDistributionHandlers(container, proteinGrams, carbGrams, fatGrams, proteinCalories, carbCalories, fatCalories, totalCalories) {
    const inputs = container.querySelectorAll('.pt-macro-input');
    const backButton = container.querySelector('#ptDistributionBackButton');
    const goButton = container.querySelector('#ptDistributionGoButton');
    const errorMessage = container.querySelector('#ptMacroDistributionError');
    
    // Back button - return to macro display
    if (backButton) {
        backButton.addEventListener('click', () => {
            // Find the macro display container (parent of this distribution table)
            const macroDisplay = container.parentElement;
            if (macroDisplay && macroDisplay.id === 'ptMacroDisplay') {
                const recommendedMacrosDiv = macroDisplay.querySelector('div:first-of-type');
                if (recommendedMacrosDiv) {
                    recommendedMacrosDiv.style.setProperty('display', 'block', 'important');
                }
            }
            container.style.setProperty('display', 'none', 'important');
        });
    }
    
    // Update totals when inputs change
    inputs.forEach(input => {
        input.addEventListener('input', () => {
            updateMacroTotals(container);
            updateMealTotals(container, proteinCalories, carbCalories, fatCalories);
        });
    });
    
    // Go button - validate and proceed
    if (goButton) {
        goButton.addEventListener('click', () => {
            const proteinTotal = parseFloat(container.querySelector('#ptProteinTotal')?.textContent) || 0;
            const fatTotal = parseFloat(container.querySelector('#ptFatTotal')?.textContent) || 0;
            const carbsTotal = parseFloat(container.querySelector('#ptCarbsTotal')?.textContent) || 0;
            
            if (Math.abs(proteinTotal - 100) > 0.01 || Math.abs(fatTotal - 100) > 0.01 || Math.abs(carbsTotal - 100) > 0.01) {
                if (errorMessage) {
                    errorMessage.style.display = 'block';
                }
                return;
            }
            
            if (errorMessage) {
                errorMessage.style.display = 'none';
            }
            
            // Save the meal plan distribution
            saveMealPlanDistribution(container, proteinGrams, carbGrams, fatGrams);
            
            // Display the finished section with meals
            displayMealPlanFinished(container, proteinGrams, carbGrams, fatGrams, totalCalories);
        });
    }
}

// Update macro column totals
function updateMacroTotals(container) {
    const proteinInputs = container.querySelectorAll('.pt-protein-input');
    const fatInputs = container.querySelectorAll('.pt-fat-input');
    const carbsInputs = container.querySelectorAll('.pt-carbs-input');
    
    let proteinTotal = 0;
    let fatTotal = 0;
    let carbsTotal = 0;
    
    proteinInputs.forEach(input => {
        proteinTotal += parseFloat(input.value) || 0;
    });
    
    fatInputs.forEach(input => {
        fatTotal += parseFloat(input.value) || 0;
    });
    
    carbsInputs.forEach(input => {
        carbsTotal += parseFloat(input.value) || 0;
    });
    
    const proteinTotalEl = container.querySelector('#ptProteinTotal');
    const fatTotalEl = container.querySelector('#ptFatTotal');
    const carbsTotalEl = container.querySelector('#ptCarbsTotal');
    
    // Round to 1 decimal place, but ensure we show exactly 100.0% if it's very close
    const formatTotal = (total) => {
        const rounded = Math.round(total * 10) / 10;
        // If within 0.05 of 100, show exactly 100.0
        if (Math.abs(rounded - 100) < 0.05) {
            return '100.0%';
        }
        return rounded + '%';
    };
    
    if (proteinTotalEl) proteinTotalEl.textContent = formatTotal(proteinTotal);
    if (fatTotalEl) fatTotalEl.textContent = formatTotal(fatTotal);
    if (carbsTotalEl) carbsTotalEl.textContent = formatTotal(carbsTotal);
}

// Update meal totals (calories per meal)
function updateMealTotals(container, proteinCalories, carbCalories, fatCalories) {
    const numMeals = container.querySelectorAll('.pt-macro-input').length / 3; // 3 macros per meal
    
    for (let i = 1; i <= numMeals; i++) {
        const proteinInput = container.querySelector(`.pt-protein-input[data-meal="${i}"]`);
        const fatInput = container.querySelector(`.pt-fat-input[data-meal="${i}"]`);
        const carbsInput = container.querySelector(`.pt-carbs-input[data-meal="${i}"]`);
        const mealTotalEl = container.querySelector(`#pt-meal-${i}-total`);
        
        if (proteinInput && fatInput && carbsInput && mealTotalEl) {
            const proteinPercent = parseFloat(proteinInput.value) || 0;
            const fatPercent = parseFloat(fatInput.value) || 0;
            const carbsPercent = parseFloat(carbsInput.value) || 0;
            
            const mealProteinCal = (proteinCalories * proteinPercent) / 100;
            const mealFatCal = (fatCalories * fatPercent) / 100;
            const mealCarbsCal = (carbCalories * carbsPercent) / 100;
            
            const mealTotal = Math.round(mealProteinCal + mealFatCal + mealCarbsCal);
            mealTotalEl.textContent = mealTotal + ' cal';
        }
    }
}

// Save meal plan distribution
function saveMealPlanDistribution(container, proteinGrams, carbGrams, fatGrams) {
    const userId = currentUser?.id || 'anonymous';
    const storageKey = `macro_user_${userId}`;
    
    const mealPlan = [];
    const numMeals = container.querySelectorAll('.pt-macro-input').length / 3;
    
    for (let i = 1; i <= numMeals; i++) {
        const proteinInput = container.querySelector(`.pt-protein-input[data-meal="${i}"]`);
        const fatInput = container.querySelector(`.pt-fat-input[data-meal="${i}"]`);
        const carbsInput = container.querySelector(`.pt-carbs-input[data-meal="${i}"]`);
        const mealNameInput = container.querySelector(`.pt-meal-name-input[data-meal="${i}"]`);
        
        if (proteinInput && fatInput && carbsInput) {
            const proteinPercent = parseFloat(proteinInput.value) || 0;
            const fatPercent = parseFloat(fatInput.value) || 0;
            const carbsPercent = parseFloat(carbsInput.value) || 0;
            const mealName = mealNameInput ? (mealNameInput.value.trim() || `Meal ${i}`) : `Meal ${i}`;
            
            mealPlan.push({
                mealNumber: i,
                mealName: mealName,
                proteinPercent: proteinPercent,
                fatPercent: fatPercent,
                carbsPercent: carbsPercent,
                proteinGrams: Math.round((proteinGrams * proteinPercent) / 100),
                fatGrams: Math.round((fatGrams * fatPercent) / 100),
                carbGrams: Math.round((carbGrams * carbsPercent) / 100)
            });
        }
    }
    
    try {
        const existingData = JSON.parse(localStorage.getItem(storageKey) || '{}');
        existingData.mealPlan = mealPlan;
        existingData.lastUpdated = new Date().toISOString();
        localStorage.setItem(storageKey, JSON.stringify(existingData));
        console.log('Saved meal plan distribution:', mealPlan);
    } catch (e) {
        console.error('Error saving meal plan distribution:', e);
    }
}

// Display finished meal plan section with copyable meals
function displayMealPlanFinished(container, proteinGrams, carbGrams, fatGrams, totalCalories) {
    // Hide the distribution table
    container.style.setProperty('display', 'none', 'important');
    
    // Find or create the finished section
    const macroDisplay = container.parentElement;
    if (!macroDisplay || macroDisplay.id !== 'ptMacroDisplay') {
        console.error('Could not find macro display container');
        return;
    }
    
    let finishedSection = macroDisplay.querySelector('#ptMealPlanFinished');
    if (!finishedSection) {
        finishedSection = document.createElement('div');
        finishedSection.id = 'ptMealPlanFinished';
        finishedSection.className = 'pt-meal-plan-finished';
        macroDisplay.appendChild(finishedSection);
    }
    
    // Get meal plan data from container
    const numMeals = container.querySelectorAll('.pt-macro-input').length / 3;
    const meals = [];
    
    for (let i = 1; i <= numMeals; i++) {
        const proteinInput = container.querySelector(`.pt-protein-input[data-meal="${i}"]`);
        const fatInput = container.querySelector(`.pt-fat-input[data-meal="${i}"]`);
        const carbsInput = container.querySelector(`.pt-carbs-input[data-meal="${i}"]`);
        const mealNameInput = container.querySelector(`.pt-meal-name-input[data-meal="${i}"]`);
        
        if (proteinInput && fatInput && carbsInput) {
            const proteinPercent = parseFloat(proteinInput.value) || 0;
            const fatPercent = parseFloat(fatInput.value) || 0;
            const carbsPercent = parseFloat(carbsInput.value) || 0;
            const mealName = mealNameInput ? (mealNameInput.value.trim() || `Meal ${i}`) : `Meal ${i}`;
            
            const mealProteinGrams = (proteinGrams * proteinPercent / 100).toFixed(1);
            const mealFatGrams = (fatGrams * fatPercent / 100).toFixed(1);
            const mealCarbsGrams = (carbGrams * carbsPercent / 100).toFixed(1);
            const mealCalories = (mealProteinGrams * 4) + (mealFatGrams * 9) + (mealCarbsGrams * 4);
            
            meals.push({
                name: mealName,
                proteinGrams: mealProteinGrams,
                fatGrams: mealFatGrams,
                carbsGrams: mealCarbsGrams,
                proteinPercent: proteinPercent,
                fatPercent: fatPercent,
                carbsPercent: carbsPercent,
                calories: mealCalories
            });
        }
    }
    
    // Calculate percentages for daily totals
    const proteinPercent = Math.round((proteinGrams * 4 / totalCalories) * 100);
    const fatPercent = Math.round((fatGrams * 9 / totalCalories) * 100);
    const carbPercent = Math.round((carbGrams * 4 / totalCalories) * 100);
    
    // Build HTML
    let mealsHTML = '';
    meals.forEach((meal, index) => {
        const mealText = `${meal.name}:\nProtein: ${meal.proteinGrams}g (${meal.proteinPercent}%)\nFat: ${meal.fatGrams}g (${meal.fatPercent}%)\nCarbs: ${meal.carbsGrams}g (${meal.carbsPercent}%)\nCalories: ${meal.calories.toFixed(0)}`;
        
        mealsHTML += `
            <div class="macro-meal-text-item" style="background: white; padding: 1rem; border-radius: 8px; margin-bottom: 1rem; border: 1px solid #dee2e6;">
                <div class="macro-meal-header" style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 0.75rem;">
                    <h5 style="margin: 0; font-size: 1rem; color: #333; font-weight: 600;">${meal.name}</h5>
                    <button class="macro-copy-btn btn btn-primary" data-meal-text="${mealText.replace(/"/g, '&quot;').replace(/\n/g, '\\n')}" onclick="copyMealMacros(this)" style="padding: 0.5rem 1rem; font-size: 0.95rem;">Copy</button>
                </div>
                <div class="macro-meal-text-content" style="color: #666; line-height: 1.8; font-size: 0.9rem;">
                    <div><strong>Protein:</strong> ${meal.proteinGrams}g (${meal.proteinPercent}%)</div>
                    <div><strong>Fat:</strong> ${meal.fatGrams}g (${meal.fatPercent}%)</div>
                    <div><strong>Carbs:</strong> ${meal.carbsGrams}g (${meal.carbsPercent}%)</div>
                    <div><strong>Calories:</strong> ${meal.calories.toFixed(0)}</div>
                </div>
            </div>
        `;
    });
    
    finishedSection.innerHTML = `
        <div style="margin-top: 1.5rem;">
            <div class="macro-meals-text">
                <h2 style="margin: 0 0 1.5rem 0; color: #333; font-size: 1.25rem; text-align: center;">Meal Breakdown</h2>
                
                <div class="macro-chatgpt-tip-collapsible" style="background: #d4edda; border: 1px solid #c3e6cb; color: #155724; padding: 0.75rem; border-radius: 8px; margin-bottom: 1.5rem;">
                    <div class="macro-chatgpt-tip-header" style="display: flex; justify-content: space-between; align-items: flex-start; gap: 0.75rem;">
                        <h4 style="margin: 0; color: #155724; flex: 1; font-size: 0.9rem; font-weight: 600;">💡 Pro Tip</h4>
                    <button type="button" class="macro-expand-btn" id="ptExpandTipBtn" aria-label="Expand tip" style="background: transparent; border: none; cursor: pointer; padding: 0.2rem; display: flex; align-items: center; justify-content: center; color: #155724; transition: transform 0.3s ease; flex-shrink: 0;">
                        <svg width="14" height="14" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                            <path d="M4 6L8 10L12 6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                        </svg>
                    </button>
                </div>
                <div class="macro-chatgpt-tip-content" id="ptChatGPTTipContent" style="display: none; padding-top: 0.75rem; animation: slideDown 0.3s ease-out;">
                    <p style="margin: 0; color: #155724; line-height: 1.6; font-size: 0.875rem;">Copy your meal macros above and paste them into ChatGPT. Ask it to create meal ideas that meet those exact macros, or tell it what you want to eat and ask how much you can have to stay within your macro targets. This makes meal planning quick and personalized!</p>
                    </div>
                </div>
                
                ${mealsHTML}
            </div>
            
            <div style="text-align: center; margin-top: 1.5rem;">
                <button type="button" id="ptFinishedBackButton" class="btn btn-secondary">Back</button>
            </div>
        </div>
    `;
    
    // Setup back button
    const backButton = finishedSection.querySelector('#ptFinishedBackButton');
    if (backButton) {
        backButton.addEventListener('click', () => {
            finishedSection.style.setProperty('display', 'none', 'important');
            container.style.setProperty('display', 'block', 'important');
        });
    }
    
    // Setup expand/collapse for pro tip
    const expandTipBtn = finishedSection.querySelector('#ptExpandTipBtn');
    const tipContent = finishedSection.querySelector('#ptChatGPTTipContent');
    if (expandTipBtn && tipContent) {
        expandTipBtn.addEventListener('click', () => {
            const isExpanded = tipContent.style.display !== 'none';
            tipContent.style.display = isExpanded ? 'none' : 'block';
            expandTipBtn.classList.toggle('expanded', !isExpanded);
            // Rotate the arrow
            const svg = expandTipBtn.querySelector('svg');
            if (svg) {
                svg.style.transform = isExpanded ? 'rotate(0deg)' : 'rotate(180deg)';
                svg.style.transition = 'transform 0.3s ease';
            }
        });
    }
    
    // Show the finished section
    finishedSection.style.setProperty('display', 'block', 'important');
}

// Copy meal macros to clipboard (global function for onclick)
if (typeof window.copyMealMacros === 'undefined') {
    window.copyMealMacros = async function(button) {
        const mealText = button.dataset.mealText.replace(/\\n/g, '\n');
        try {
            await navigator.clipboard.writeText(mealText);
            // Show feedback
            const originalText = button.textContent;
            button.textContent = 'Copied!';
            button.style.background = '#4CAF50';
            setTimeout(() => {
                button.textContent = originalText;
                button.style.background = '#1877f2';
            }, 2000);
        } catch (error) {
            console.error('Failed to copy:', error);
            // Fallback: select text
            const textElement = button.closest('.macro-meal-text-item').querySelector('.macro-meal-text-content');
            if (textElement) {
                const range = document.createRange();
                range.selectNodeContents(textElement);
                const selection = window.getSelection();
                selection.removeAllRanges();
                selection.addRange(range);
            }
        }
    };
}

// Setup handlers for editable macro percentages
function setupMacroPercentageHandlers(container, totalCalories) {
    const proteinPercentInput = container.querySelector('#ptProteinPercent');
    const carbPercentInput = container.querySelector('#ptCarbPercent');
    const fatPercentInput = container.querySelector('#ptFatPercent');
    const errorMessage = container.querySelector('#ptMacroPercentError');
    
    const proteinGramsDisplay = container.querySelector('#ptProteinGrams');
    const carbGramsDisplay = container.querySelector('#ptCarbGrams');
    const fatGramsDisplay = container.querySelector('#ptFatGrams');
    const proteinCaloriesDisplay = container.querySelector('#ptProteinCalories');
    const carbCaloriesDisplay = container.querySelector('#ptCarbCalories');
    const fatCaloriesDisplay = container.querySelector('#ptFatCalories');
    
    function updateMacrosFromPercentages() {
        const proteinPercent = parseFloat(proteinPercentInput.value) || 0;
        const carbPercent = parseFloat(carbPercentInput.value) || 0;
        const fatPercent = parseFloat(fatPercentInput.value) || 0;
        
        const total = proteinPercent + carbPercent + fatPercent;
        
        if (Math.abs(total - 100) > 0.01) {
            // Show error if not equal to 100%
            if (errorMessage) {
                errorMessage.style.display = 'block';
            }
            return;
        }
        
        // Hide error if valid
        if (errorMessage) {
            errorMessage.style.display = 'none';
        }
        
        // Calculate calories for each macro
        const proteinCalories = Math.round((totalCalories * proteinPercent) / 100);
        const carbCalories = Math.round((totalCalories * carbPercent) / 100);
        const fatCalories = Math.round((totalCalories * fatPercent) / 100);
        
        // Calculate grams
        const proteinGrams = Math.round(proteinCalories / 4);
        const carbGrams = Math.round(carbCalories / 4);
        const fatGrams = Math.round(fatCalories / 9);
        
        // Update displays
        if (proteinGramsDisplay) proteinGramsDisplay.textContent = proteinGrams + 'g';
        if (carbGramsDisplay) carbGramsDisplay.textContent = carbGrams + 'g';
        if (fatGramsDisplay) fatGramsDisplay.textContent = fatGrams + 'g';
        if (proteinCaloriesDisplay) proteinCaloriesDisplay.textContent = proteinCalories + ' cal';
        if (carbCaloriesDisplay) carbCaloriesDisplay.textContent = carbCalories + ' cal';
        if (fatCaloriesDisplay) fatCaloriesDisplay.textContent = fatCalories + ' cal';
    }
    
    function adjustPercentagesToSum100(changedInput) {
        const proteinPercent = parseFloat(proteinPercentInput.value) || 0;
        const carbPercent = parseFloat(carbPercentInput.value) || 0;
        const fatPercent = parseFloat(fatPercentInput.value) || 0;
        
        const total = proteinPercent + carbPercent + fatPercent;
        const diff = 100 - total;
        
        if (Math.abs(diff) < 0.01) {
            updateMacrosFromPercentages();
            return;
        }
        
        // Adjust the other two inputs proportionally
        if (changedInput === proteinPercentInput) {
            // Adjust carbs and fat proportionally
            const otherTotal = carbPercent + fatPercent;
            if (otherTotal > 0) {
                const carbAdjustment = (carbPercent / otherTotal) * diff;
                const fatAdjustment = (fatPercent / otherTotal) * diff;
                carbPercentInput.value = Math.round((carbPercent + carbAdjustment) * 100) / 100;
                fatPercentInput.value = Math.round((fatPercent + fatAdjustment) * 100) / 100;
            } else {
                // If both are 0, split the difference equally
                carbPercentInput.value = Math.round((diff / 2) * 100) / 100;
                fatPercentInput.value = Math.round((diff / 2) * 100) / 100;
            }
        } else if (changedInput === carbPercentInput) {
            // Adjust protein and fat proportionally
            const otherTotal = proteinPercent + fatPercent;
            if (otherTotal > 0) {
                const proteinAdjustment = (proteinPercent / otherTotal) * diff;
                const fatAdjustment = (fatPercent / otherTotal) * diff;
                proteinPercentInput.value = Math.round((proteinPercent + proteinAdjustment) * 100) / 100;
                fatPercentInput.value = Math.round((fatPercent + fatAdjustment) * 100) / 100;
            } else {
                proteinPercentInput.value = Math.round((diff / 2) * 100) / 100;
                fatPercentInput.value = Math.round((diff / 2) * 100) / 100;
            }
        } else if (changedInput === fatPercentInput) {
            // Adjust protein and carbs proportionally
            const otherTotal = proteinPercent + carbPercent;
            if (otherTotal > 0) {
                const proteinAdjustment = (proteinPercent / otherTotal) * diff;
                const carbAdjustment = (carbPercent / otherTotal) * diff;
                proteinPercentInput.value = Math.round((proteinPercent + proteinAdjustment) * 100) / 100;
                carbPercentInput.value = Math.round((carbPercent + carbAdjustment) * 100) / 100;
            } else {
                proteinPercentInput.value = Math.round((diff / 2) * 100) / 100;
                carbPercentInput.value = Math.round((diff / 2) * 100) / 100;
            }
        }
        
        // Round to whole numbers
        proteinPercentInput.value = Math.round(parseFloat(proteinPercentInput.value));
        carbPercentInput.value = Math.round(parseFloat(carbPercentInput.value));
        fatPercentInput.value = Math.round(parseFloat(fatPercentInput.value));
        
        updateMacrosFromPercentages();
    }
    
    // Add event listeners
    if (proteinPercentInput) {
        proteinPercentInput.addEventListener('input', () => adjustPercentagesToSum100(proteinPercentInput));
        proteinPercentInput.addEventListener('blur', () => {
            if (parseFloat(proteinPercentInput.value) < 0) proteinPercentInput.value = 0;
            if (parseFloat(proteinPercentInput.value) > 100) proteinPercentInput.value = 100;
            adjustPercentagesToSum100(proteinPercentInput);
        });
    }
    
    if (carbPercentInput) {
        carbPercentInput.addEventListener('input', () => adjustPercentagesToSum100(carbPercentInput));
        carbPercentInput.addEventListener('blur', () => {
            if (parseFloat(carbPercentInput.value) < 0) carbPercentInput.value = 0;
            if (parseFloat(carbPercentInput.value) > 100) carbPercentInput.value = 100;
            adjustPercentagesToSum100(carbPercentInput);
        });
    }
    
    if (fatPercentInput) {
        fatPercentInput.addEventListener('input', () => adjustPercentagesToSum100(fatPercentInput));
        fatPercentInput.addEventListener('blur', () => {
            if (parseFloat(fatPercentInput.value) < 0) fatPercentInput.value = 0;
            if (parseFloat(fatPercentInput.value) > 100) fatPercentInput.value = 100;
            adjustPercentagesToSum100(fatPercentInput);
        });
    }
}

