// Ensure macro calculator is initialized in personal trainer view
function ensureMacroCalculatorInitialized() {
    // Check if macro calculator exists in any of the personal trainer content areas
    const ptMyInfoContent = document.getElementById('ptMyInfoContent');
    const ptActivityLevelContent = document.getElementById('ptActivityLevelContent');
    const ptMealPlanContent = document.getElementById('ptMealPlanContent');
    
    // Check if any content area has the macro calculator
    const hasCalculator = (ptMyInfoContent && ptMyInfoContent.querySelector('.macro-calculator-container')) ||
                         (ptActivityLevelContent && ptActivityLevelContent.querySelector('.macro-calculator-container')) ||
                         (ptMealPlanContent && ptMealPlanContent.querySelector('.macro-calculator-container'));
    
    if (!hasCalculator && typeof getMacroCalculatorHTML === 'function') {
        // Initialize macro calculator in a hidden container first
        const tempContainer = document.createElement('div');
        tempContainer.style.display = 'none';
        tempContainer.innerHTML = getMacroCalculatorHTML();
        document.body.appendChild(tempContainer);
        
        // Setup event listeners, but we'll override the activity factor button
        // Note: We don't call setupMacroCalculatorListeners here because it adds listeners
        // that conflict with our personal trainer handlers. We handle events ourselves.
        
        // Store the calculator HTML for later use
        window.ptMacroCalculatorHTML = tempContainer.innerHTML;
        document.body.removeChild(tempContainer);
        
        // Setup personal trainer progression handlers
        setupPersonalTrainerProgression();
    } else if (!window.ptProgressionSetup) {
        // Setup progression handlers if not already set up
        setupPersonalTrainerProgression();
    }
}

// Setup progression handlers for personal trainer tabs
function setupPersonalTrainerProgression() {
    if (window.ptProgressionSetup) return; // Prevent duplicate setup
    window.ptProgressionSetup = true;
    
    // Override form Go button to navigate to Body Fat tab
    // Use capture phase to intercept before other handlers
    document.addEventListener('click', function(e) {
        const target = e.target;
        
        // Check if we're in personal trainer view by checking if personal trainer content is visible
        const personalTrainerContent = document.getElementById('personalTrainerContent');
        const ptActivityLevelContent = document.getElementById('ptActivityLevelContent');
        const ptMyInfoContent = document.getElementById('ptMyInfoContent');
        
        if (!personalTrainerContent || personalTrainerContent.style.display === 'none') {
            return; // Not in personal trainer view
        }
        
        // My Info form Go button → Show body fat section (stays in my-info tab)
        if (target.id === 'macroFormGoButton' && ptMyInfoContent.contains(target)) {
            // Get form values and validate
            const form = document.getElementById('macroCalcForm');
            if (form && form.checkValidity()) {
                // Don't prevent default - let the original handler process the form
                // The body fat section will be shown in the same tab
            }
        }
        
        // Body Fat Back button → Go back to My Goals tab
        if (target.id === 'macroBodyFatBackButton' && ptMyInfoContent && ptMyInfoContent.contains(target)) {
            e.preventDefault();
            e.stopPropagation();
            
            // Go back to My Goals tab
            switchPersonalTrainerTab('my-goals');
        }
        
        // Body Fat Go button → Save all data and go to Activity Level tab
        if (target.id === 'macroBodyFatGoButton' && ptMyInfoContent && ptMyInfoContent.contains(target)) {
            // Validate form first
            const form = document.getElementById('macroCalcForm');
            const bodyFatInput = document.getElementById('macroBodyfat');
            
            if (form && form.checkValidity() && bodyFatInput && bodyFatInput.value) {
                // Collect all form data
                const age = document.getElementById('macroAge')?.value;
                const gender = document.getElementById('macroGender')?.value;
                const height = document.getElementById('macroHeight')?.value;
                const weight = document.getElementById('macroWeight')?.value;
                const bodyFat = bodyFatInput.value;
                
                // Save to localStorage (user-specific)
                const userId = currentUser?.id || 'anonymous';
                const storageKey = `macro_user_${userId}`;
                
                try {
                    const existingData = JSON.parse(localStorage.getItem(storageKey) || '{}');
                    const userData = {
                        ...existingData,
                        age: age,
                        gender: gender,
                        height: height,
                        weight: weight,
                        bodyFat: bodyFat,
                        lastUpdated: new Date().toISOString()
                    };
                    localStorage.setItem(storageKey, JSON.stringify(userData));
                    
                    // Don't prevent default - let the original handler process first
                    // Then switch to activity level tab after a short delay
                    setTimeout(() => {
                        switchPersonalTrainerTab('activity-level');
                    }, 200);
                } catch (e) {
                    console.error('Error saving user info:', e);
                    alert('Error saving information. Please try again.');
                }
            } else {
                // If form is invalid, show validation messages
                if (form && !form.checkValidity()) {
                    form.reportValidity();
                }
                if (!bodyFatInput || !bodyFatInput.value) {
                    bodyFatInput?.reportValidity();
                }
            }
        }
        
        // Activity Level Back button → Go to My Info tab
        if (target.id === 'macroActivityFactorBackButton' && ptActivityLevelContent && ptActivityLevelContent.contains(target)) {
            e.preventDefault();
            e.stopPropagation();
            
            // Go back to my info tab
            switchPersonalTrainerTab('my-info');
        }
        
        // Activity Level Go button → Save activity factor, calculate calories, and go to Meal Plan tab
        if (target.id === 'macroActivityFactorGoButton' && ptActivityLevelContent && ptActivityLevelContent.contains(target)) {
            e.preventDefault();
            e.stopPropagation();
            
            const activitySelect = document.getElementById('macroActivityFactor');
            if (activitySelect && activitySelect.value) {
                const activityFactorValue = activitySelect.value;
                console.log('Activity factor selected:', activityFactorValue);
                
                // Save activity factor to localStorage
                const userId = currentUser?.id || 'anonymous';
                const storageKey = `macro_user_${userId}`;
                try {
                    const existingData = JSON.parse(localStorage.getItem(storageKey) || '{}');
                    existingData.activityFactor = activityFactorValue;
                    existingData.lastUpdated = new Date().toISOString();
                    localStorage.setItem(storageKey, JSON.stringify(existingData));
                    console.log('Saved activity factor to localStorage:', existingData);
                } catch (e) {
                    console.error('Error saving activity factor:', e);
                }
                
                // Calculate calories using Katch-McArdle formula
                calculatePersonalTrainerCalories();
                
                // Switch to meal plan tab after calculation
                setTimeout(() => {
                    switchPersonalTrainerTab('meal-plan');
                }, 300);
            } else {
                console.warn('Activity factor not selected or element not found');
            }
        }
        
        // Meal Plan Go button → Calculate and display recommended macros
        const ptMealPlanContent = document.getElementById('ptMealPlanContent');
        if (target.id === 'macroMealPlanButton' && ptMealPlanContent && ptMealPlanContent.contains(target)) {
            e.preventDefault();
            e.stopPropagation();
            
            const numberOfMealsInput = document.getElementById('macroMeals');
            if (!numberOfMealsInput || !numberOfMealsInput.value) {
                alert('Please enter the number of meals');
                return;
            }
            
            const numberOfMeals = parseInt(numberOfMealsInput.value);
            if (isNaN(numberOfMeals) || numberOfMeals < 1 || numberOfMeals > 10) {
                alert('Please enter a valid number of meals (1-10)');
                return;
            }
            
            // Save number of meals to localStorage
            const userId = currentUser?.id || 'anonymous';
            const storageKey = `macro_user_${userId}`;
            try {
                const existingData = JSON.parse(localStorage.getItem(storageKey) || '{}');
                existingData.numberOfMeals = numberOfMeals;
                existingData.lastUpdated = new Date().toISOString();
                localStorage.setItem(storageKey, JSON.stringify(existingData));
                console.log('Saved number of meals to localStorage:', numberOfMeals);
            } catch (e) {
                console.error('Error saving number of meals:', e);
            }
            
            // Check if user has reached calculation limit (async IIFE)
            (async () => {
                const accessCheck = await canCalculateMealPlan();
                if (!accessCheck.allowed) {
                    const message = accessCheck.locked 
                        ? `You have reached your limit of ${accessCheck.limit} meal plan calculation${accessCheck.limit === 1 ? '' : 's'}. Please upgrade to continue.`
                        : `You have reached your limit of ${accessCheck.limit} meal plan calculations. Please upgrade to Tier Two or higher for more calculations.`;
                    // Show upgrade modal instead of alert
                    if (accessCheck.locked) {
                        showUpgradeModal(message, 'Meal Plan Calculations');
                    } else {
                        alert(message);
                    }
                    return;
                }
                
                console.log('Calculating recommended macros for', numberOfMeals, 'meals');
                
                // Calculate recommended macros
                const macros = calculateRecommendedMacros();
                if (!macros) {
                    alert('Error calculating macros. Please ensure all information has been entered correctly.');
                    return;
                }
                
                console.log('Calculated macros:', macros);
                
                // Display the macros
                await displayRecommendedMacros(macros, numberOfMeals);
            })();
        }
        
        // Meal Plan Display Back button → Go back to number of meals input
        if (target.id === 'macroMealPlanDisplayBackButton' && ptMealPlanContent && ptMealPlanContent.contains(target)) {
            e.preventDefault();
            e.stopPropagation();
            
            const macroDisplay = ptMealPlanContent.querySelector('#ptMacroDisplay');
            const mealPlanSection = ptMealPlanContent.querySelector('#macroMealPlanSection');
            const caloriesHeader = ptMealPlanContent.querySelector('#ptMealPlanCaloriesHeader');
            
            if (macroDisplay) {
                macroDisplay.style.setProperty('display', 'none', 'important');
            }
            if (mealPlanSection) {
                mealPlanSection.style.setProperty('display', 'block', 'important');
            }
            // Show the "Total Daily Calories" header again
            if (caloriesHeader) {
                caloriesHeader.style.setProperty('display', 'block', 'important');
            }
        }
        
        // Meal Plan Section Back button → Go back to activity level (when in number of meals input)
        if (target.id === 'macroMealPlanSectionBackButton' && ptMealPlanContent && ptMealPlanContent.contains(target)) {
            e.preventDefault();
            e.stopPropagation();
            
            // Check if we're in the number of meals input section or the macro display
            const macroDisplay = ptMealPlanContent.querySelector('#ptMacroDisplay');
            const isMacroDisplayVisible = macroDisplay && macroDisplay.style.display !== 'none' && window.getComputedStyle(macroDisplay).display !== 'none';
            
            if (isMacroDisplayVisible) {
                // If macro display is visible, hide it and show the number of meals input
                const mealPlanSection = ptMealPlanContent.querySelector('#macroMealPlanSection');
                const caloriesHeader = ptMealPlanContent.querySelector('#ptMealPlanCaloriesHeader');
                
                if (macroDisplay) {
                    macroDisplay.style.setProperty('display', 'none', 'important');
                }
                
                if (caloriesHeader) {
                    caloriesHeader.style.setProperty('display', 'block', 'important');
                }
                
                if (mealPlanSection) {
                    mealPlanSection.style.setProperty('display', 'block', 'important');
                }
            } else {
                // If we're in the number of meals input section, go back to activity level tab
                switchPersonalTrainerTab('activity-level');
            }
        }
    }, true); // Use capture phase to intercept before other handlers
    
    // Also remove the original event listener if it exists
    const activityFactorGoButton = document.getElementById('macroActivityFactorGoButton');
    if (activityFactorGoButton) {
        // Clone the button to remove all event listeners
        const newButton = activityFactorGoButton.cloneNode(true);
        activityFactorGoButton.parentNode.replaceChild(newButton, activityFactorGoButton);
        // Our capture phase handler will still catch it
    }
}

