// Initialize macro calculator - sets up event listeners
function initMacroCalculator() {
    // This function is called when macro view is shown
    // The HTML is built by getMacroCalculatorHTML() and inserted into macroContent
    const macroContent = document.getElementById('macroContent');
    if (macroContent && !macroContent.querySelector('.macro-calculator-container')) {
        macroContent.innerHTML = getMacroCalculatorHTML();
        setupMacroCalculatorListeners();
    }
}

// Setup macro calculator event listeners
function setupMacroCalculatorListeners() {
    // Form submission handler
    const form = document.getElementById('macroCalcForm');
    if (form) {
        form.addEventListener('submit', (e) => {
            e.preventDefault();
            // Save form data
            const userId = currentUser?.id || 'anonymous';
            const storageKey = `macro_user_${userId}`;
            const formData = {
                age: document.getElementById('macroAge')?.value,
                gender: document.getElementById('macroGender')?.value,
                height: document.getElementById('macroHeight')?.value,
                weight: document.getElementById('macroWeight')?.value
            };
            try {
                const existingData = JSON.parse(localStorage.getItem(storageKey) || '{}');
                localStorage.setItem(storageKey, JSON.stringify({ ...existingData, ...formData }));
            } catch (e) {
                console.error('Error saving form data:', e);
            }
            // Show body fat section
            const bodyFatSection = document.getElementById('macroBodyFatSection');
            if (bodyFatSection) {
                form.style.display = 'none';
                bodyFatSection.style.display = 'block';
            }
        });
    }
    
    // Body fat Go button
    const bodyFatGoButton = document.getElementById('macroBodyFatGoButton');
    if (bodyFatGoButton) {
        bodyFatGoButton.addEventListener('click', () => {
            const bodyFat = document.getElementById('macroBodyfat')?.value;
            if (bodyFat) {
                const userId = currentUser?.id || 'anonymous';
                const storageKey = `macro_user_${userId}`;
                try {
                    const existingData = JSON.parse(localStorage.getItem(storageKey) || '{}');
                    existingData.bodyFat = bodyFat;
                    localStorage.setItem(storageKey, JSON.stringify(existingData));
                } catch (e) {
                    console.error('Error saving body fat:', e);
                }
                // Show activity factor section
                const bodyFatSection = document.getElementById('macroBodyFatSection');
                const activitySection = document.getElementById('macroActivityFactorSection');
                if (bodyFatSection && activitySection) {
                    bodyFatSection.style.display = 'none';
                    activitySection.style.display = 'block';
                }
            }
        });
    }
    
    // Activity factor Go button
    const activityGoButton = document.getElementById('macroActivityFactorGoButton');
    if (activityGoButton) {
        activityGoButton.addEventListener('click', () => {
            const activityFactor = document.getElementById('macroActivityFactor')?.value;
            if (activityFactor) {
                const userId = currentUser?.id || 'anonymous';
                const storageKey = `macro_user_${userId}`;
                try {
                    const existingData = JSON.parse(localStorage.getItem(storageKey) || '{}');
                    existingData.activityFactor = activityFactor;
                    localStorage.setItem(storageKey, JSON.stringify(existingData));
                    // Calculate and show meal plan
                    calculatePersonalTrainerCalories();
                    const activitySection = document.getElementById('macroActivityFactorSection');
                    const mealPlanSection = document.getElementById('macroMealPlanSection');
                    if (activitySection && mealPlanSection) {
                        activitySection.style.display = 'none';
                        mealPlanSection.style.display = 'block';
                    }
                } catch (e) {
                    console.error('Error saving activity factor:', e);
                }
            }
        });
    }
    
    // Meal plan Go button
    const mealPlanGoButton = document.getElementById('macroMealPlanGoButton');
    if (mealPlanGoButton) {
        mealPlanGoButton.addEventListener('click', async () => {
            // Check if user has reached calculation limit
            const accessCheck = await canCalculateMealPlan();
            if (!accessCheck.allowed) {
                const message = accessCheck.locked 
                    ? `You have reached your limit of ${accessCheck.limit} meal plan calculation${accessCheck.limit === 1 ? '' : 's'}. Please upgrade to continue.`
                    : `You have reached your limit of ${accessCheck.limit} meal plan calculations. Please upgrade to Tier Two or higher for more calculations.`;
                // Show upgrade modal instead of alert
                if (accessCheck.locked) {
                    showUpgradeModal(message, 'Meal Plan Calculations');
                } else {
                    alert(message);
                }
                return;
            }
            
            const numMeals = parseInt(document.getElementById('macroNumberOfMeals')?.value || '3');
            const macros = calculateRecommendedMacros();
            if (macros) {
                await displayRecommendedMacros(macros, numMeals);
            }
        });
    }
}

// Extract section from macro calculator HTML
function extractMacroSection(sectionId) {
    // Ensure macro calculator HTML is available
    if (!window.ptMacroCalculatorHTML) {
        if (typeof getMacroCalculatorHTML === 'function') {
            window.ptMacroCalculatorHTML = getMacroCalculatorHTML();
        } else {
            console.error('getMacroCalculatorHTML function not found');
            return '';
        }
    }
    
    if (!window.ptMacroCalculatorHTML) {
        console.error('ptMacroCalculatorHTML is empty');
        return '';
    }
    
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = window.ptMacroCalculatorHTML;
    const section = tempDiv.querySelector(`#${sectionId}`);
    if (section) {
        // Clone the section and make it visible
        const clonedSection = section.cloneNode(true);
        clonedSection.style.display = 'block';
        clonedSection.removeAttribute('style'); // Remove inline display:none if present
        clonedSection.style.setProperty('display', 'block', 'important');
        return clonedSection.outerHTML;
    } else {
        console.error(`Section #${sectionId} not found in macro calculator HTML`);
        console.log('Available sections:', tempDiv.querySelectorAll('[id]').map(el => el.id));
    }
    return '';
}

// Switch Personal Trainer tab
async function switchPersonalTrainerTab(tab) {
    console.log('[PERSONAL_TRAINER_DEBUG] switchPersonalTrainerTab called with tab:', tab);
    
    // Save inputs before switching tabs (for Tier Three/Four)
    await saveMealPlanInputs();
    
    const ptMyGoalsTab = document.getElementById('ptMyGoalsTab');
    const ptMyInfoTab = document.getElementById('ptMyInfoTab');
    const ptBodyFatTab = document.getElementById('ptBodyFatTab');
    const ptActivityLevelTab = document.getElementById('ptActivityLevelTab');
    const ptMealPlanTab = document.getElementById('ptMealPlanTab');
    const ptMyGoalsContent = document.getElementById('ptMyGoalsContent');
    const ptMyInfoContent = document.getElementById('ptMyInfoContent');
    const ptBodyFatContent = document.getElementById('ptBodyFatContent');
    const ptActivityLevelContent = document.getElementById('ptActivityLevelContent');
    const ptMealPlanContent = document.getElementById('ptMealPlanContent');
    
    console.log('[PERSONAL_TRAINER_DEBUG] Tab elements found:', {
        myGoalsTab: !!ptMyGoalsTab,
        myInfoTab: !!ptMyInfoTab,
        activityLevelTab: !!ptActivityLevelTab,
        mealPlanTab: !!ptMealPlanTab
    });
    console.log('[PERSONAL_TRAINER_DEBUG] Content elements found:', {
        myGoalsContent: !!ptMyGoalsContent,
        myInfoContent: !!ptMyInfoContent,
        activityLevelContent: !!ptActivityLevelContent,
        mealPlanContent: !!ptMealPlanContent
    });
    
    // Remove active class from all tabs
    if (ptMyGoalsTab) ptMyGoalsTab.classList.remove('active');
    if (ptMyInfoTab) ptMyInfoTab.classList.remove('active');
    if (ptBodyFatTab) ptBodyFatTab.classList.remove('active');
    if (ptActivityLevelTab) ptActivityLevelTab.classList.remove('active');
    if (ptMealPlanTab) ptMealPlanTab.classList.remove('active');
    
    // Hide all content
    if (ptMyGoalsContent) ptMyGoalsContent.style.display = 'none';
    if (ptMyInfoContent) ptMyInfoContent.style.display = 'none';
    if (ptBodyFatContent) ptBodyFatContent.style.display = 'none';
    if (ptActivityLevelContent) ptActivityLevelContent.style.display = 'none';
    if (ptMealPlanContent) ptMealPlanContent.style.display = 'none';
    
    // Ensure macro calculator is initialized
    ensureMacroCalculatorInitialized();
    
    // Load saved inputs for Tier Three/Four
    const savedInputs = await loadMealPlanInputs();
    
    // Show selected tab and content
    if (tab === 'my-goals') {
        if (ptMyGoalsTab) ptMyGoalsTab.classList.add('active');
        if (ptMyGoalsContent) {
            ptMyGoalsContent.style.display = 'block';
            // Always refresh the content to get latest user info
            ptMyGoalsContent.innerHTML = buildMyInfoContent();
            // Setup form submit handler
            setupMyInfoForm();
        }
    } else if (tab === 'my-info') {
        if (ptMyInfoTab) ptMyInfoTab.classList.add('active');
        if (ptMyInfoContent) {
            ptMyInfoContent.style.display = 'block';
            // Show the form section (Age, Gender, Height, Weight) and body fat section
            if (ptMyInfoContent.innerHTML.trim() === '' || !ptMyInfoContent.querySelector('#macroCalcForm')) {
                // Ensure macro calculator HTML is initialized
                ensureMacroCalculatorInitialized();
                
                const formHTML = extractMacroSection('macroCalcForm');
                const bodyFatHTML = extractMacroSection('macroBodyFatSection');
                
                // If extraction failed, use the full HTML directly
                if (!formHTML || !bodyFatHTML) {
                    console.warn('Failed to extract macro sections, using full HTML');
                    if (typeof getMacroCalculatorHTML === 'function') {
                        const fullHTML = getMacroCalculatorHTML();
                        ptMyInfoContent.innerHTML = fullHTML;
                    } else {
                        ptMyInfoContent.innerHTML = '<p>Error loading form. Please refresh the page.</p>';
                        return;
                    }
                } else {
                    ptMyInfoContent.innerHTML = `
                        <div class="macro-calculator-container">
                            <div class="macro-title-section">
                                <h2 style="font-size: 1.25rem; text-align: center; margin-bottom: 1.5rem; color: #333;">My Info</h2>
                            </div>
                            ${formHTML}
                            ${bodyFatHTML}
                        </div>
                    `;
                }
                // Make sure both sections are visible
                setTimeout(() => {
                    const form = ptMyInfoContent.querySelector('#macroCalcForm');
                    const bodyFatSection = ptMyInfoContent.querySelector('#macroBodyFatSection');
                    const formGoButton = ptMyInfoContent.querySelector('#macroFormGoButton');
                    if (form) {
                        form.style.setProperty('display', 'block', 'important');
                        // Hide the form Go button since we'll use body fat Go button instead
                        if (formGoButton) {
                            formGoButton.style.setProperty('display', 'none', 'important');
                        }
                    }
                    if (bodyFatSection) {
                        bodyFatSection.style.setProperty('display', 'block', 'important');
                    }
                    
                    // Load saved inputs for Tier Three/Four
                    if (savedInputs && savedInputs.info) {
                        const info = savedInputs.info;
                        if (info.age) document.getElementById('macroAge').value = info.age;
                        if (info.gender) document.getElementById('macroGender').value = info.gender;
                        if (info.height) document.getElementById('macroHeight').value = info.height;
                        if (info.weight) document.getElementById('macroWeight').value = info.weight;
                        if (info.bodyFat) document.getElementById('macroBodyfat').value = info.bodyFat;
                    }
                }, 50);
                // Setup event listeners if not already set up
                if (typeof setupMacroCalculatorListeners === 'function') {
                    setupMacroCalculatorListeners();
                }
            } else {
                // Ensure both sections are visible if content already exists
                const form = ptMyInfoContent.querySelector('#macroCalcForm');
                const bodyFatSection = ptMyInfoContent.querySelector('#macroBodyFatSection');
                const formGoButton = ptMyInfoContent.querySelector('#macroFormGoButton');
                if (form) {
                    form.style.setProperty('display', 'block', 'important');
                    // Hide the form Go button since we'll use body fat Go button instead
                    if (formGoButton) {
                        formGoButton.style.setProperty('display', 'none', 'important');
                    }
                }
                if (bodyFatSection) {
                    bodyFatSection.style.setProperty('display', 'block', 'important');
                }
            }
        }
    } else if (tab === 'activity-level') {
        // Activity Level tab button may not exist in DOM (hidden from header)
        // but we can still show the content programmatically
        if (ptActivityLevelTab) ptActivityLevelTab.classList.add('active');
        if (ptActivityLevelContent) {
            ptActivityLevelContent.style.display = 'block';
            // Show only the activity factor section
            if (ptActivityLevelContent.innerHTML.trim() === '' || !ptActivityLevelContent.querySelector('#macroActivityFactorSection')) {
                // Ensure macro calculator HTML is initialized
                ensureMacroCalculatorInitialized();
                
                const activityHTML = extractMacroSection('macroActivityFactorSection');
                
                // If extraction failed, use the full HTML directly
                if (!activityHTML) {
                    console.warn('Failed to extract activity section, using full HTML');
                    if (typeof getMacroCalculatorHTML === 'function') {
                        const fullHTML = getMacroCalculatorHTML();
                        ptActivityLevelContent.innerHTML = fullHTML;
                        // Hide all sections except activity factor
                        setTimeout(() => {
                            const form = ptActivityLevelContent.querySelector('#macroCalcForm');
                            const bodyFat = ptActivityLevelContent.querySelector('#macroBodyFatSection');
                            const mealPlan = ptActivityLevelContent.querySelector('#macroMealPlanSection');
                            const results = ptActivityLevelContent.querySelector('#macroResultsSection');
                            const activity = ptActivityLevelContent.querySelector('#macroActivityFactorSection');
                            if (form) form.style.display = 'none';
                            if (bodyFat) bodyFat.style.display = 'none';
                            if (mealPlan) mealPlan.style.display = 'none';
                            if (results) results.style.display = 'none';
                            if (activity) activity.style.setProperty('display', 'block', 'important');
                            
                            // Load saved inputs for Tier Three/Four
                            if (savedInputs && savedInputs.activity) {
                                const activityData = savedInputs.activity;
                                if (activityData.activityFactor) {
                                    document.getElementById('macroActivityFactor').value = activityData.activityFactor;
                                }
                            }
                        }, 50);
                    } else {
                        ptActivityLevelContent.innerHTML = '<p>Error loading form. Please refresh the page.</p>';
                        return;
                    }
                } else if (activityHTML) {
                    ptActivityLevelContent.innerHTML = `
                        <div class="macro-calculator-container">
                            ${activityHTML}
                        </div>
                    `;
                    // Make sure the section is visible and load saved activity factor
                    setTimeout(() => {
                        const section = ptActivityLevelContent.querySelector('#macroActivityFactorSection');
                        if (section) {
                            section.style.setProperty('display', 'block', 'important');
                        }
                        // Load saved activity factor (prefer database for Tier Three/Four, fallback to localStorage)
                        const activitySelect = document.getElementById('macroActivityFactor');
                        if (activitySelect) {
                            if (savedInputs && savedInputs.activity && savedInputs.activity.activityFactor) {
                                activitySelect.value = savedInputs.activity.activityFactor;
                                console.log('Loaded saved activity factor from database:', savedInputs.activity.activityFactor);
                            } else {
                                // Fallback to localStorage
                                const userId = currentUser?.id || 'anonymous';
                                const storageKey = `macro_user_${userId}`;
                                try {
                                    const macroData = JSON.parse(localStorage.getItem(storageKey) || '{}');
                                    if (macroData.activityFactor) {
                                        activitySelect.value = macroData.activityFactor;
                                        console.log('Loaded saved activity factor from localStorage:', macroData.activityFactor);
                                    }
                                } catch (e) {
                                    console.error('Error loading activity factor:', e);
                                }
                            }
                        }
                    }, 50);
                    // Don't call setupMacroCalculatorListeners - we handle events ourselves in personal trainer view
                    // Override the activity factor button handler to prevent original calculateMacros from running
                    const activityFactorGoButton = ptActivityLevelContent.querySelector('#macroActivityFactorGoButton');
                    if (activityFactorGoButton) {
                        // Remove any existing listeners by cloning
                        const newButton = activityFactorGoButton.cloneNode(true);
                        activityFactorGoButton.parentNode.replaceChild(newButton, activityFactorGoButton);
                    }
                }
            } else {
                // Ensure section is visible if content already exists
                const section = ptActivityLevelContent.querySelector('#macroActivityFactorSection');
                if (section) {
                    section.style.setProperty('display', 'block', 'important');
                }
                // Load saved activity factor
                const userId = currentUser?.id || 'anonymous';
                const storageKey = `macro_user_${userId}`;
                try {
                    const macroData = JSON.parse(localStorage.getItem(storageKey) || '{}');
                    if (macroData.activityFactor) {
                        const activitySelect = document.getElementById('macroActivityFactor');
                        if (activitySelect) {
                            activitySelect.value = macroData.activityFactor;
                            console.log('Loaded saved activity factor:', macroData.activityFactor);
                        }
                    }
                } catch (e) {
                    console.error('Error loading activity factor:', e);
                }
                // Override the activity factor button handler
                const activityFactorGoButton = ptActivityLevelContent.querySelector('#macroActivityFactorGoButton');
                if (activityFactorGoButton) {
                    // Remove any existing listeners by cloning
                    const newButton = activityFactorGoButton.cloneNode(true);
                    activityFactorGoButton.parentNode.replaceChild(newButton, activityFactorGoButton);
                }
            }
        }
    } else if (tab === 'meal-plan') {
        if (ptMealPlanTab) ptMealPlanTab.classList.add('active');
        if (ptMealPlanContent) {
            ptMealPlanContent.style.display = 'block';
            
            // Check if number of meals is already saved
            const userId = currentUser?.id || 'anonymous';
            const storageKey = `macro_user_${userId}`;
            const macroData = JSON.parse(localStorage.getItem(storageKey) || '{}');
            const savedNumberOfMeals = macroData.numberOfMeals ? parseInt(macroData.numberOfMeals) : null;
            
            // Check if macro display is already visible (user navigated back from distribution table)
            const macroDisplay = ptMealPlanContent.querySelector('#ptMacroDisplay');
            const isMacroDisplayVisible = macroDisplay && macroDisplay.style.display !== 'none' && window.getComputedStyle(macroDisplay).display !== 'none';
            
            // Only auto-show macros if they're already displayed (user came back from distribution table)
            // Otherwise, always show the number of meals input first
            if (isMacroDisplayVisible && savedNumberOfMeals && savedNumberOfMeals >= 1 && savedNumberOfMeals <= 10) {
                // Macros are already displayed, keep them visible
                return; // Exit early since macros are already displayed
            }
            
            // Hide any existing macro display to show the input section
            if (macroDisplay) {
                macroDisplay.style.setProperty('display', 'none', 'important');
            }
            
            // Show only the calories header and meal plan section (no table, no instruction section)
            if (ptMealPlanContent.innerHTML.trim() === '' || !ptMealPlanContent.querySelector('#macroMealPlanSection')) {
                // Ensure macro calculator HTML is initialized
                ensureMacroCalculatorInitialized();
                
                const resultsHTML = extractMacroSection('macroResultsSection');
                const mealPlanHTML = extractMacroSection('macroMealPlanSection');
                
                // If extraction failed, use the full HTML directly
                if (!resultsHTML || !mealPlanHTML) {
                    console.warn('Failed to extract meal plan sections, using full HTML');
                    if (typeof getMacroCalculatorHTML === 'function') {
                        const fullHTML = getMacroCalculatorHTML();
                        ptMealPlanContent.innerHTML = fullHTML;
                        // Hide all sections except meal plan
                        setTimeout(() => {
                            const form = ptMealPlanContent.querySelector('#macroCalcForm');
                            const bodyFat = ptMealPlanContent.querySelector('#macroBodyFatSection');
                            const activity = ptMealPlanContent.querySelector('#macroActivityFactorSection');
                            const results = ptMealPlanContent.querySelector('#macroResultsSection');
                            const mealPlan = ptMealPlanContent.querySelector('#macroMealPlanSection');
                            if (form) form.style.display = 'none';
                            if (bodyFat) bodyFat.style.display = 'none';
                            if (activity) activity.style.display = 'none';
                            if (results) results.style.display = 'none';
                            if (mealPlan) mealPlan.style.setProperty('display', 'block', 'important');
                        }, 50);
                    } else {
                        ptMealPlanContent.innerHTML = '<p>Error loading form. Please refresh the page.</p>';
                        return;
                    }
                } else if (resultsHTML && mealPlanHTML) {
                    ptMealPlanContent.innerHTML = `
                        <div class="macro-calculator-container">
                            <div id="ptMealPlanCaloriesHeader" style="text-align: center; margin-bottom: 1.5rem;">
                                <h2 style="margin-bottom: 0.5rem; font-size: 1.25rem; color: #333;">Total Daily Calories</h2>
                                <h1 id="ptMealPlanCalories" class="macro-result-calories" style="text-align: center; font-size: 2.5rem; margin: 0; color: #1877f2;"></h1>
                            </div>
                            ${mealPlanHTML}
                        </div>
                    `;
                    // Make sure meal plan section is visible
                    setTimeout(async () => {
                        const mealPlanSection = ptMealPlanContent.querySelector('#macroMealPlanSection');
                        if (mealPlanSection) {
                            mealPlanSection.style.setProperty('display', 'block', 'important');
                            // Hide the instruction section that shows user choices
                            const instructionsHeader = mealPlanSection.querySelector('.macro-meal-plan-instructions');
                            if (instructionsHeader) {
                                instructionsHeader.style.setProperty('display', 'none', 'important');
                            }
                            // Pre-fill number of meals if saved
                            if (savedNumberOfMeals) {
                                const mealsInput = mealPlanSection.querySelector('#macroMeals');
                                if (mealsInput) {
                                    mealsInput.value = savedNumberOfMeals;
                                }
                            }
                            // Add tier_one calculation limit indicator
                            const accessCheck = await canCalculateMealPlan();
                            if (accessCheck.limit !== null) {
                                // Remove existing indicator if any
                                const existingIndicator = mealPlanSection.querySelector('.tier-one-limit-indicator');
                                if (existingIndicator) {
                                    existingIndicator.remove();
                                }
                                // Add new indicator
                                const indicator = document.createElement('div');
                                indicator.className = 'tier-one-limit-indicator';
                                indicator.style.cssText = 'margin-bottom: 1rem; padding: 0.75rem; background-color: #fff3cd; border: 1px solid #ffc107; border-radius: 4px; color: #856404; font-size: 0.9rem;';
                                if (accessCheck.allowed) {
                                    indicator.textContent = `You have ${accessCheck.remaining} meal plan calculation${accessCheck.remaining === 1 ? '' : 's'} remaining.`;
                                } else {
                                    indicator.textContent = 'You have reached your limit of 2 meal plan calculations. Please upgrade to Tier Two or higher for more calculations.';
                                    indicator.style.backgroundColor = '#f8d7da';
                                    indicator.style.borderColor = '#dc3545';
                                    indicator.style.color = '#721c24';
                                }
                                // Insert before the first input or button
                                const firstInput = mealPlanSection.querySelector('input, button');
                                if (firstInput) {
                                    mealPlanSection.insertBefore(indicator, firstInput.parentElement || firstInput);
                                } else {
                                    mealPlanSection.insertBefore(indicator, mealPlanSection.firstChild);
                                }
                            }
                        }
                        // Load saved data and calculate calories
                        setTimeout(() => {
                            loadPersonalTrainerDataAndCalculate();
                        }, 100);
                    }, 50);
                    // Don't call setupMacroCalculatorListeners - we handle events ourselves
                }
            } else {
                // Ensure meal plan section is visible if content already exists
                const mealPlanSection = ptMealPlanContent.querySelector('#macroMealPlanSection');
                if (mealPlanSection) {
                    mealPlanSection.style.setProperty('display', 'block', 'important');
                    // Add/update tier_one calculation limit indicator
                    (async () => {
                        const accessCheck = await canCalculateMealPlan();
                        if (accessCheck.limit !== null) {
                            // Remove existing indicator if any
                            const existingIndicator = mealPlanSection.querySelector('.tier-one-limit-indicator');
                            if (existingIndicator) {
                                existingIndicator.remove();
                            }
                            // Add new indicator
                            const indicator = document.createElement('div');
                            indicator.className = 'tier-one-limit-indicator';
                            indicator.style.cssText = 'margin-bottom: 1rem; padding: 0.75rem; background-color: #fff3cd; border: 1px solid #ffc107; border-radius: 4px; color: #856404; font-size: 0.9rem;';
                            if (accessCheck.allowed) {
                                indicator.textContent = `You have ${accessCheck.remaining} meal plan calculation${accessCheck.remaining === 1 ? '' : 's'} remaining.`;
                            } else {
                                indicator.textContent = `You have reached your limit of ${accessCheck.limit} meal plan calculation${accessCheck.limit === 1 ? '' : 's'}. Please upgrade to continue.`;
                                indicator.style.backgroundColor = '#f8d7da';
                                indicator.style.borderColor = '#dc3545';
                                indicator.style.color = '#721c24';
                            }
                            // Insert before the first input or button
                            const firstInput = mealPlanSection.querySelector('input, button');
                            if (firstInput) {
                                mealPlanSection.insertBefore(indicator, firstInput.parentElement || firstInput);
                            } else {
                                mealPlanSection.insertBefore(indicator, mealPlanSection.firstChild);
                            }
                        }
                    })();
                    // Hide the instruction section that shows user choices
                    const instructionsHeader = mealPlanSection.querySelector('.macro-meal-plan-instructions');
                    if (instructionsHeader) {
                        instructionsHeader.style.setProperty('display', 'none', 'important');
                    }
                    // Pre-fill number of meals if saved
                    if (savedNumberOfMeals) {
                        const mealsInput = mealPlanSection.querySelector('#macroMeals');
                        if (mealsInput) {
                            mealsInput.value = savedNumberOfMeals;
                        }
                    }
                }
                // Load saved data and calculate calories
                loadPersonalTrainerDataAndCalculate();
            }
        }
    }
}

// Switch Personal Strength Coach tab
function switchPersonalStrengthCoachTab(tab) {
    const pscPRCalcTab = document.getElementById('pscPRCalcTab');
    const pscPRLogTab = document.getElementById('pscPRLogTab');
    const pscProgressiveOverloadTab = document.getElementById('pscProgressiveOverloadTab');
    const pscPRCalcContent = document.getElementById('pscPRCalcContent');
    const pscPRLogContent = document.getElementById('pscPRLogContent');
    const pscProgressiveOverloadContent = document.getElementById('pscProgressiveOverloadContent');
    
    // Remove active class from all tabs
    if (pscPRCalcTab) pscPRCalcTab.classList.remove('active');
    if (pscPRLogTab) pscPRLogTab.classList.remove('active');
    if (pscProgressiveOverloadTab) pscProgressiveOverloadTab.classList.remove('active');
    
    // Hide all content
    if (pscPRCalcContent) pscPRCalcContent.style.display = 'none';
    if (pscPRLogContent) pscPRLogContent.style.display = 'none';
    if (pscProgressiveOverloadContent) pscProgressiveOverloadContent.style.display = 'none';
    
    // Show selected tab and content
    if (tab === 'pr-calc') {
        if (pscPRCalcTab) pscPRCalcTab.classList.add('active');
        if (pscPRCalcContent) {
            pscPRCalcContent.style.display = 'block';
            // Always reload content to ensure it's fresh and listeners are set up
            pscPRCalcContent.innerHTML = buildPRCalculatorUI();
            // Use setTimeout to ensure DOM is updated before setting up listeners
            setTimeout(() => {
                setupPRCalculatorListeners();
            }, 0);
        }
    } else if (tab === 'pr-log') {
        if (pscPRLogTab) pscPRLogTab.classList.add('active');
        if (pscPRLogContent) {
            pscPRLogContent.style.display = 'block';
            // Always reload content to ensure it's fresh
            pscPRLogContent.innerHTML = buildPRLogUI();
            // Use setTimeout to ensure DOM is updated before loading logs
            setTimeout(() => {
                loadPRLogs();
            }, 0);
        }
    } else if (tab === 'progressive-overload') {
        if (pscProgressiveOverloadTab) pscProgressiveOverloadTab.classList.add('active');
        if (pscProgressiveOverloadContent) {
            pscProgressiveOverloadContent.style.display = 'block';
            // Always reload content to ensure it's fresh
            pscProgressiveOverloadContent.innerHTML = buildProgressiveOverloadUI();
            // Setup toggle functionality and load PR logs
            setTimeout(async () => {
                setupProgressiveOverloadToggle();
                await loadProgressiveOverloadLifts();
            }, 0);
        }
    }
}
